// ─── Types ───────────────────────────────────────────────────────────────────

type MatchStatus = "matched" | "fuzzy" | "unmatched" | "quarantined" | "mapped";

interface CleansingEntry {
  id: string;
  rawValue: string;            // Original unprocessed text from the BOQ sheet
  detectedPartNumber?: string;
  normalizedName?: string;
  matchStatus: MatchStatus;
  confidence: number;          // 0–100
  matchedSkuId?: string;       // CatalogSKU.id if matched
  matchedPartNumber?: string;
  mappedOutput?: string;       // User-defined override mapping
  vendor?: string;
  flagReason?: string;
  reviewedAt?: string;
}

interface CleansingViewProps {
  catalogSkus: CatalogSKU[];
}

// ─── Mock BOQ raw entries to demonstrate the workshop ────────────────────────

function generateMockEntries(catalogSkus: CatalogSKU[]): CleansingEntry[] {
  const raws = [
    { raw: "32-Core CPU HPE Gen11", part: "P40424-B21", vendor: "HPE" },
    { raw: "Intel Xeon 6130 16-core legacy proc", part: "815100-B21", vendor: "HPE" },
    { raw: "dell 3.84tb nvme ssd sff", part: "400-BPSB", vendor: "Dell" },
    { raw: "Cisco UCS 64GB DDR5 memory dimm", part: "UCS-MR-64G1XS-E", vendor: "Cisco" },
    { raw: "8x2.5 HDD SAS drive cage", part: undefined, vendor: "HPE" },
    { raw: "Juniper QFX5120-48Y switch 1U", part: undefined, vendor: "Juniper" },
    { raw: "P40424B21", part: "P40424-B21", vendor: "HPE" },   // missing hyphen
    { raw: "400 BPSB 3.84TB", part: "400-BPSB", vendor: "Dell" }, // space instead of hyphen
    { raw: "Xeon Gold 6430 Processor", part: "P40424-B21", vendor: "HPE" },
    { raw: "HPE Gen 11 redundant power supply 800W", part: undefined, vendor: "HPE" },
    { raw: "Cisco 9300-24UX Switch", part: undefined, vendor: "Cisco" },
    { raw: "Dell PowerEdge RAID H755 controller", part: undefined, vendor: "Dell" },
  ];

  return raws.map((r, idx) => {
    const catalogMatch = catalogSkus.find(
      (sku) => sku.partNumber === r.part && sku.vendor === r.vendor
    );

    let status: MatchStatus;
    let confidence: number;

    if (catalogMatch && r.raw.toLowerCase().includes(r.part?.replace(/-/g, "").toLowerCase() || "")) {
      status = "matched";
      confidence = 98;
    } else if (catalogMatch) {
      status = "fuzzy";
      confidence = Math.floor(Math.random() * 20) + 72;
    } else if (r.part) {
      status = "unmatched";
      confidence = Math.floor(Math.random() * 30) + 40;
    } else {
      status = idx % 3 === 0 ? "quarantined" : "unmatched";
      confidence = Math.floor(Math.random() * 35) + 15;
    }

    return {
      id: `entry-${idx + 1}`,
      rawValue: r.raw,
      detectedPartNumber: r.part,
      normalizedName: catalogMatch?.name,
      matchStatus: status,
      confidence,
      matchedSkuId: catalogMatch?.id,
      matchedPartNumber: catalogMatch?.partNumber,
      vendor: r.vendor,
      flagReason: status === "quarantined" ? "No SKU pattern detected — manual mapping required" : undefined,
    };
  });
}

// ─── Status Config ────────────────────────────────────────────────────────────

const STATUS_CONFIG: Record<MatchStatus, { label: string; color: string; bg: string; border: string; dot: string }> = {
  matched:     { label: "Exact Match",   color: "text-emerald-400", bg: "bg-emerald-500/8",  border: "border-emerald-500/20", dot: "bg-emerald-400" },
  fuzzy:       { label: "Fuzzy Match",   color: "text-amber-400",   bg: "bg-amber-500/8",    border: "border-amber-500/20",   dot: "bg-amber-400" },
  unmatched:   { label: "Unmatched",     color: "text-orange-400",  bg: "bg-orange-500/8",   border: "border-orange-500/20",  dot: "bg-orange-400" },
  quarantined: { label: "Quarantined",   color: "text-red-400",     bg: "bg-red-500/8",      border: "border-red-500/20",     dot: "bg-red-400 animate-pulse" },
  mapped:      { label: "Mapped",        color: "text-indigo-400",  bg: "bg-indigo-500/8",   border: "border-indigo-500/20",  dot: "bg-indigo-400" },
};

// ─── Component ────────────────────────────────────────────────────────────────

export function CleansingView({ catalogSkus }: CleansingViewProps) {
  const { toast } = useToast();

  const [entries, setEntries] = useState<CleansingEntry[]>(() =>
    generateMockEntries(catalogSkus)
  );
  const [searchTerm, setSearchTerm] = useState("");
  const [filterStatus, setFilterStatus] = useState<MatchStatus | "all">("all");
  const [selectedEntryId, setSelectedEntryId] = useState<string | null>(null);
  const [skuSearchTerm, setSkuSearchTerm] = useState("");
  const [isRunningAutoMap, setIsRunningAutoMap] = useState(false);
  const [expandedEntry, setExpandedEntry] = useState<string | null>(null);

  // Derived stats
  const stats = useMemo(() => ({
    total: entries.length,
    matched: entries.filter((e) => e.matchStatus === "matched").length,
    fuzzy: entries.filter((e) => e.matchStatus === "fuzzy").length,
    unmatched: entries.filter((e) => e.matchStatus === "unmatched").length,
    quarantined: entries.filter((e) => e.matchStatus === "quarantined").length,
    mapped: entries.filter((e) => e.matchStatus === "mapped").length,
  }), [entries]);

  const coveragePercent = useMemo(() => {
    const covered = stats.matched + stats.mapped + stats.fuzzy;
    return stats.total > 0 ? Math.round((covered / stats.total) * 100) : 0;
  }, [stats]);

  // Filtered list
  const filteredEntries = useMemo(() => {
    return entries.filter((e) => {
      const matchesSearch =
        !searchTerm ||
        e.rawValue.toLowerCase().includes(searchTerm.toLowerCase()) ||
        e.detectedPartNumber?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        e.normalizedName?.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesFilter = filterStatus === "all" || e.matchStatus === filterStatus;
      return matchesSearch && matchesFilter;
    });
  }, [entries, searchTerm, filterStatus]);

  // Catalog suggestions for mapping panel
  const catalogSuggestions = useMemo(() => {
    const term = skuSearchTerm.toLowerCase();
    if (!term) return catalogSkus.slice(0, 8);
    return catalogSkus
      .filter(
        (sku) =>
          sku.status === "active" &&
          (sku.partNumber.toLowerCase().includes(term) ||
            sku.name.toLowerCase().includes(term) ||
            sku.vendor.toLowerCase().includes(term))
      )
      .slice(0, 8);
  }, [catalogSkus, skuSearchTerm]);

  // Auto-map runner
  const handleAutoMap = useCallback(async () => {
    setIsRunningAutoMap(true);
    try {
      await apiClient.post("/api/taxonomy/rules", {
        sourceId: "batch-cleansing",
        ruleType: "substitution",
        explanation: "Batch auto-cleansing run",
      });
    } catch {
      // Mock: continue regardless
    }

    // Promote fuzzy → matched + unmatched with detected part → fuzzy
    setEntries((prev) =>
      prev.map((e) => {
        if (e.matchStatus === "fuzzy" && e.confidence >= 70) {
          return { ...e, matchStatus: "matched", confidence: Math.min(e.confidence + 12, 99), reviewedAt: new Date().toISOString() };
        }
        if (e.matchStatus === "unmatched" && e.detectedPartNumber) {
          const skuMatch = catalogSkus.find((s) => s.partNumber === e.detectedPartNumber);
          if (skuMatch) {
            return {
              ...e,
              matchStatus: "fuzzy",
              matchedSkuId: skuMatch.id,
              matchedPartNumber: skuMatch.partNumber,
              normalizedName: skuMatch.name,
              confidence: 74,
            };
          }
        }
        return e;
      })
    );

    setIsRunningAutoMap(false);
    toast(`Auto-mapping complete! ${stats.fuzzy} fuzzy entries resolved.`, "success");
  }, [catalogSkus, stats.fuzzy, toast]);

  // Manual map entry to a catalog SKU
  const handleManualMap = useCallback((entryId: string, sku: CatalogSKU) => {
    setEntries((prev) =>
      prev.map((e) =>
        e.id === entryId
          ? {
              ...e,
              matchStatus: "mapped",
              mappedOutput: sku.partNumber,
              matchedSkuId: sku.id,
              matchedPartNumber: sku.partNumber,
              normalizedName: sku.name,
              confidence: 100,
              reviewedAt: new Date().toISOString(),
            }
          : e
      )
    );
    setSelectedEntryId(null);
    toast(`Mapped to ${sku.partNumber} — ${sku.name}`, "success");
  }, [toast]);

  // Quarantine an entry
  const handleQuarantine = useCallback((entryId: string) => {
    setEntries((prev) =>
      prev.map((e) =>
        e.id === entryId
          ? { ...e, matchStatus: "quarantined", flagReason: "Manually quarantined for review" }
          : e
      )
    );
    toast("Entry quarantined for manual review.", "warn");
  }, [toast]);

  // Download cleansed mapping as CSV
  const handleExportCSV = useCallback(() => {
    const rows = [
      ["ID", "Raw Value", "Detected Part #", "Mapped Part #", "Normalized Name", "Vendor", "Status", "Confidence %"],
      ...entries.map((e) => [
        e.id,
        `"${e.rawValue}"`,
        e.detectedPartNumber || "",
        e.mappedOutput || e.matchedPartNumber || "",
        `"${e.normalizedName || ""}"`,
        e.vendor || "",
        e.matchStatus,
        e.confidence.toString(),
      ]),
    ];
    const csv = rows.map((r) => r.join(",")).join("\n");
    const blob = new Blob([csv], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `vsip-cleansing-${new Date().toISOString().split("T")[0]}.csv`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    toast("Cleansed mapping exported as CSV.", "success");
  }, [entries, toast]);

  const selectedEntry = entries.find((e) => e.id === selectedEntryId);

  return (
    <motion.div
      className="flex flex-col gap-5"
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.35, ease: "easeOut" }}
    >
      {/* Header */}
      <div
        className="p-5 rounded-xl border"
        style={{ background: "rgba(7,10,19,0.8)", borderColor: "rgba(74,133,253,0.12)" }}
      >
        <div className="flex items-start justify-between gap-4 flex-wrap">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-emerald-500/10 border border-emerald-500/20 flex items-center justify-center">
              <Scissors className="w-5 h-5 text-emerald-400" />
            </div>
            <div>
              <h1 className="text-sm font-bold text-white">
                Interactive Splicing &amp; Mapping Workshop
              </h1>
              <p className="text-[11px] text-gray-500 mt-0.5">
                PRD §3.6 — Quarantine, fuzzy-match, and canonicalize raw BOQ line items against the Master Catalog
              </p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button
              onClick={handleExportCSV}
              className="flex items-center gap-1.5 text-[11px] font-bold px-3 py-2 rounded-lg bg-white/5 border border-white/10 text-gray-300 hover:bg-white/10 transition cursor-pointer"
            >
              <Download className="w-3.5 h-3.5" /> Export CSV
            </button>
            <button
              onClick={handleAutoMap}
              disabled={isRunningAutoMap}
              className="flex items-center gap-1.5 text-[11px] font-bold px-3.5 py-2 rounded-lg bg-emerald-500 hover:bg-emerald-600 text-white transition cursor-pointer disabled:opacity-50"
            >
              {isRunningAutoMap ? <RefreshCw className="w-3.5 h-3.5 animate-spin" /> : <Zap className="w-3.5 h-3.5 text-yellow-300" />}
              Auto-Map
            </button>
          </div>
        </div>

        {/* Stats row */}
        <div className="flex flex-wrap gap-3 mt-4">
          {(["all", "matched", "fuzzy", "unmatched", "quarantined", "mapped"] as const).map((s) => {
            const count = s === "all" ? stats.total : stats[s as keyof typeof stats];
            const cfg = s === "all" ? null : STATUS_CONFIG[s as MatchStatus];
            return (
              <button
                key={s}
                onClick={() => setFilterStatus(s)}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase font-mono transition cursor-pointer border ${
                  filterStatus === s
                    ? "bg-indigo-500/15 border-indigo-500/40 text-indigo-300"
                    : "bg-white/5 border-white/8 text-gray-500 hover:text-gray-300"
                }`}
              >
                {cfg && <span className={`w-1.5 h-1.5 rounded-full ${cfg.dot}`} />}
                {s === "all" ? "All" : STATUS_CONFIG[s as MatchStatus].label} ({count})
              </button>
            );
          })}
          {/* Coverage bar */}
          <div className="ml-auto flex items-center gap-3 text-[10px] text-gray-500">
            <span className="font-mono">Coverage</span>
            <div className="w-24 h-2 bg-white/5 rounded-full overflow-hidden">
              <motion.div
                className="h-full rounded-full bg-gradient-to-r from-emerald-500 to-indigo-500"
                initial={{ width: 0 }}
                animate={{ width: `${coveragePercent}%` }}
                transition={{ duration: 0.8, ease: "easeOut" }}
              />
            </div>
            <span className="text-white font-bold font-mono">{coveragePercent}%</span>
          </div>
        </div>
      </div>

      {/* Main workspace: two-panel layout */}
      <div className="grid grid-cols-1 lg:grid-cols-5 gap-4">
        {/* Left: Entry list */}
        <div className="lg:col-span-3 flex flex-col gap-3">
          {/* Search bar */}
          <div className="flex items-center gap-2 px-3 py-2 rounded-lg border bg-black/20 border-white/5">
            <Search className="w-3.5 h-3.5 text-gray-500 shrink-0" />
            <input
              type="text"
              placeholder="Search raw values, part numbers, SKU names..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="flex-1 bg-transparent text-xs text-white placeholder-gray-600 focus:outline-none"
            />
            {searchTerm && (
              <button onClick={() => setSearchTerm("")} className="text-gray-600 hover:text-gray-400">
                <X className="w-3.5 h-3.5" />
              </button>
            )}
          </div>

          {/* Entry cards */}
          <div className="space-y-1.5">
            <AnimatePresence initial={false}>
              {filteredEntries.map((entry, idx) => {
                const cfg = STATUS_CONFIG[entry.matchStatus];
                const isSelected = selectedEntryId === entry.id;
                const isExpanded = expandedEntry === entry.id;

                return (
                  <motion.div
                    key={entry.id}
                    initial={{ opacity: 0, x: -8 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -8 }}
                    transition={{ duration: 0.2, delay: idx * 0.02 }}
                    className={`rounded-lg border transition-all cursor-pointer ${
                      isSelected
                        ? "border-indigo-500/40 bg-indigo-500/5"
                        : "border-white/5 bg-black/15 hover:border-white/10"
                    }`}
                    onClick={() => {
                      setSelectedEntryId(isSelected ? null : entry.id);
                      setSkuSearchTerm(entry.detectedPartNumber || entry.rawValue.split(" ")[0]);
                    }}
                  >
                    <div className="flex items-start gap-3 p-3">
                      {/* Status dot */}
                      <div className={`mt-1 w-2 h-2 rounded-full shrink-0 ${cfg.dot}`} />

                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 flex-wrap mb-0.5">
                          <span className="text-[11px] font-bold text-white truncate max-w-[200px]" title={entry.rawValue}>
                            {entry.rawValue}
                          </span>
                          <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded font-mono uppercase ${cfg.color} ${cfg.bg} ${cfg.border} border`}>
                            {cfg.label}
                          </span>
                          {entry.vendor && (
                            <span className="text-[9px] text-gray-500">{entry.vendor}</span>
                          )}
                        </div>

                        {entry.matchedPartNumber && (
                          <div className="flex items-center gap-1.5 text-[10px] text-gray-400 mt-0.5">
                            <span className="font-mono text-indigo-300">{entry.matchedPartNumber}</span>
                            <ArrowRight className="w-3 h-3 text-gray-700" />
                            <span className="truncate max-w-[240px]">{entry.normalizedName}</span>
                          </div>
                        )}

                        {entry.flagReason && (
                          <p className="text-[9px] text-red-400 mt-0.5">{entry.flagReason}</p>
                        )}
                      </div>

                      {/* Confidence bar */}
                      <div className="shrink-0 text-right">
                        <p className="text-[9px] text-gray-600 font-mono mb-1">{entry.confidence}%</p>
                        <div className="w-12 h-1 bg-white/5 rounded-full overflow-hidden">
                          <div
                            className="h-full rounded-full"
                            style={{
                              width: `${entry.confidence}%`,
                              background: entry.confidence >= 90 ? "#00d4a0" : entry.confidence >= 70 ? "#ff9b36" : "#ff3d5a",
                            }}
                          />
                        </div>
                      </div>
                    </div>
                  </motion.div>
                );
              })}
            </AnimatePresence>

            {filteredEntries.length === 0 && (
              <div className="flex flex-col items-center justify-center py-16 gap-3 text-center">
                <Filter className="w-8 h-8 text-gray-700" />
                <p className="text-sm text-gray-500">No entries match the current filter</p>
              </div>
            )}
          </div>
        </div>

        {/* Right: Mapping panel */}
        <div className="lg:col-span-2">
          <AnimatePresence mode="wait">
            {selectedEntry ? (
              <motion.div
                key={selectedEntry.id}
                initial={{ opacity: 0, y: 8 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: 8 }}
                transition={{ duration: 0.2 }}
                className="sticky top-0 rounded-xl border border-indigo-500/20 bg-indigo-500/5 p-4 flex flex-col gap-4"
              >
                <div className="flex items-start justify-between gap-2">
                  <div>
                    <p className="text-[9px] text-gray-500 font-mono uppercase tracking-wider">Mapping Panel</p>
                    <p className="text-[11px] font-bold text-white mt-0.5 leading-relaxed">
                      "{selectedEntry.rawValue}"
                    </p>
                    <div className="flex items-center gap-2 mt-1">
                      <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded font-mono uppercase border ${STATUS_CONFIG[selectedEntry.matchStatus].color} ${STATUS_CONFIG[selectedEntry.matchStatus].bg} ${STATUS_CONFIG[selectedEntry.matchStatus].border}`}>
                        {STATUS_CONFIG[selectedEntry.matchStatus].label}
                      </span>
                      <span className="text-[9px] text-gray-500 font-mono">{selectedEntry.confidence}% confidence</span>
                    </div>
                  </div>
                  <div className="flex items-center gap-1">
                    <button
                      onClick={() => handleQuarantine(selectedEntry.id)}
                      className="p-1.5 rounded hover:bg-red-500/10 text-red-400 hover:text-red-300 transition cursor-pointer"
                      title="Quarantine"
                    >
                      <AlertTriangle className="w-3.5 h-3.5" />
                    </button>
                    <button
                      onClick={() => setSelectedEntryId(null)}
                      className="p-1.5 rounded hover:bg-white/5 text-gray-500 hover:text-gray-300 transition cursor-pointer"
                    >
                      <X className="w-3.5 h-3.5" />
                    </button>
                  </div>
                </div>

                {/* Current mapping */}
                {selectedEntry.matchedPartNumber && (
                  <div className="p-2.5 rounded-lg bg-black/25 border border-white/5">
                    <p className="text-[9px] text-gray-500 font-mono uppercase mb-1.5">Current Mapping</p>
                    <div className="flex items-center gap-2">
                      <Link2 className="w-3.5 h-3.5 text-emerald-400 shrink-0" />
                      <div>
                        <p className="text-[11px] font-bold text-emerald-300 font-mono">{selectedEntry.matchedPartNumber}</p>
                        <p className="text-[10px] text-gray-400">{selectedEntry.normalizedName}</p>
                      </div>
                      <CheckCircle2 className="w-4 h-4 text-emerald-400 ml-auto shrink-0" />
                    </div>
                  </div>
                )}

                {/* Catalog search */}
                <div>
                  <p className="text-[9px] text-gray-500 font-mono uppercase tracking-wider mb-2">Override / Remap</p>
                  <div className="flex items-center gap-2 px-2.5 py-2 rounded-lg border border-white/8 bg-black/20 mb-2">
                    <Search className="w-3 h-3 text-gray-600 shrink-0" />
                    <input
                      type="text"
                      placeholder="Search catalog..."
                      value={skuSearchTerm}
                      onChange={(e) => setSkuSearchTerm(e.target.value)}
                      className="flex-1 bg-transparent text-[11px] text-white placeholder-gray-700 focus:outline-none font-mono"
                    />
                  </div>
                  <div className="space-y-1 max-h-52 overflow-y-auto">
                    {catalogSuggestions.map((sku) => (
                      <button
                        key={sku.id}
                        onClick={() => handleManualMap(selectedEntry.id, sku)}
                        className="w-full text-left flex items-start gap-2 p-2 rounded-lg hover:bg-white/5 border border-transparent hover:border-indigo-500/20 transition group cursor-pointer"
                      >
                        <div className="flex-1 min-w-0">
                          <p className="text-[10px] font-bold text-indigo-200 font-mono">{sku.partNumber}</p>
                          <p className="text-[9px] text-gray-500 truncate">{sku.name}</p>
                          <div className="flex items-center gap-2 mt-0.5">
                            <span className="text-[8px] text-gray-600">{sku.vendor}</span>
                            <span className="text-[8px] text-emerald-400 font-mono">${sku.price.toLocaleString()}</span>
                            <span
                              className={`text-[8px] font-mono ${
                                sku.status === "active" ? "text-emerald-400" : sku.status === "eol" ? "text-red-400" : "text-amber-400"
                              }`}
                            >
                              {sku.status.toUpperCase()}
                            </span>
                          </div>
                        </div>
                        <ArrowRight className="w-3.5 h-3.5 text-gray-600 group-hover:text-indigo-400 transition shrink-0 mt-0.5" />
                      </button>
                    ))}
                    {catalogSuggestions.length === 0 && (
                      <p className="text-[10px] text-gray-600 text-center py-4">No catalog matches</p>
                    )}
                  </div>
                </div>
              </motion.div>
            ) : (
              <motion.div
                key="empty"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="rounded-xl border border-white/5 bg-black/10 flex flex-col items-center justify-center py-16 gap-3 text-center"
              >
                <div className="w-12 h-12 rounded-full bg-emerald-500/8 border border-emerald-500/15 flex items-center justify-center">
                  <Eye className="w-5 h-5 text-emerald-400/40" />
                </div>
                <div>
                  <p className="text-sm text-gray-500 font-medium">Select an entry</p>
                  <p className="text-[11px] text-gray-600 mt-0.5">
                    Click any BOQ line to open the mapping panel
                  </p>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
    </motion.div>
  );
}

import { tokens } from "../../styles/tokens";
import { useState, useMemo } from "react";
import { motion } from "motion/react";
import {
  Globe,
  Database,
  Activity,
  Target,
  AlertTriangle,
  ChevronRight,
  Zap,
  RefreshCw,
  Loader2,
} from "lucide-react";
import { UCID_STEPS } from "../../lib/mockData";
import { useChartDimensions } from "../../hooks/useChartDimensions";
import type { AppView, UCID, Vendor, ForensicIssue } from "../../types";
import { ErrorBoundary } from "../shared/ErrorBoundary";

import { KpiCard } from "./KpiCard";
import { VendorHealthList } from "./VendorHealthList";
import { ActiveIssuesList } from "./ActiveIssuesList";
import { CatalogTrendAnalyzer } from "./CatalogTrendAnalyzer";
import { VendorStatusBoard } from "./VendorStatusBoard";

interface DashboardProps {
  onNavigate: (v: AppView) => void;
  ucids: UCID[];
  vendors: Vendor[];
  forensicIssues: ForensicIssue[];
}

export function Dashboard({
  onNavigate,
  ucids,
  vendors,
  forensicIssues,
}: DashboardProps) {
  const [hovered, setHovered] = useState<string | null>(null);
  const areaChart = useChartDimensions();
  const pieChart = useChartDimensions();

  const activeUCIDs = useMemo(() => ucids.filter((u) => u.currentStep !== "snapshot"), [ucids]);
  const criticalIssues = useMemo(() => forensicIssues.filter(
    (f) => f.severity === "critical" && f.status !== "resolved",
  ).length, [forensicIssues]);
  const connectedVendors = useMemo(() => vendors.filter(
    (v) => v.status === "connected" || v.status === "syncing",
  ).length, [vendors]);
  const totalCatalog = useMemo(() => vendors.reduce((s, v) => s + v.catalogItems, 0), [vendors]);

  const VENDOR_PIE = useMemo(() => vendors.map((v) => ({
    name: v.shortName,
    value: v.catalogItems,
    color: v.color,
  })), [vendors]);

    const averagePipeline = useMemo(() => {
      return activeUCIDs.length > 0 
        ? Math.round(activeUCIDs.reduce((acc, u) => {
            const stepIdx = UCID_STEPS.findIndex((s) => s.id === u.currentStep);
            return acc + (stepIdx / (UCID_STEPS.length - 1)) * 100;
        }, 0) / activeUCIDs.length)
        : 0;
    }, [activeUCIDs]);

    const recentMission = useMemo(() => {
      return activeUCIDs.length > 0 ? activeUCIDs[0].displayId : "No active missions";
    }, [activeUCIDs]);

  const syncStatusInfo = useMemo(() => {
    const hasError = vendors.some((v) => v.status === "error");
    const hasSyncing = vendors.some((v) => v.status === "syncing");
    const countConnected = vendors.filter((v) => v.status === "connected" || v.status === "syncing").length;

    let value = "Synced";
    let delta = "Healthy";
    let color = tokens.colors.status.success; 
    if (hasError) {
      value = "Error";
      delta = "Check APIs";
      color = tokens.colors.status.error; 
    } else if (hasSyncing) {
      value = "Syncing";
      delta = "Optimizing";
      color = tokens.colors.status.warning; 
    }

    return {
      value,
      sub: `${countConnected} of ${vendors.length} online`,
      delta,
      color,
    };
  }, [vendors]);

  const KPI_CARDS = useMemo(() => [
    {
      id: "vendor-portal",
      label: "Connected Vendors",
      value: `${connectedVendors}`,
      sub: `of ${vendors.length} total`,
      icon: Globe,
      color: tokens.colors.accent.indigo, 
      delta: "",
      up: true,
    },
    {
      id: "catalog",
      label: "Catalog SKUs",
      value: totalCatalog.toLocaleString(),
      sub: `across ${vendors.length} vendors`,
      icon: Database,
      color: tokens.colors.status.success, 
      delta: "",
      up: true,
    },
    {
      id: "mission-control",
      label: "Active UCIDs",
      value: `${activeUCIDs.length}`,
      sub: `${ucids.length} total missions`,
      icon: Target,
      color: tokens.colors.status.warning, 
      delta: "",
      up: true,
    },
    {
      id: "forensic",
      label: "Open Issues",
      value: `${forensicIssues.filter((f) => f.status !== "resolved").length}`,
      sub: `${criticalIssues} critical`,
      icon: Activity,
      color: tokens.colors.status.error, 
      delta: "",
      up: false,
    },
    {
      id: "mission-control",
      label: "Active Pipeline",
      value: `${averagePipeline}%`,
      sub: `${recentMission} processing`,
      icon: Zap,
      color: tokens.colors.accent.violet, 
      delta: "Live",
      up: true,
    },
    {
      id: "catalog",
      label: "Last Sync Status",
      value: syncStatusInfo.value,
      sub: syncStatusInfo.sub,
      icon: RefreshCw,
      color: syncStatusInfo.color,
      delta: syncStatusInfo.delta,
      up: syncStatusInfo.value !== "Error",
    },
  ], [connectedVendors, vendors.length, totalCatalog, activeUCIDs.length, ucids.length, forensicIssues, criticalIssues, averagePipeline, recentMission, syncStatusInfo]);

  // Memoized Render for Pipeline Loop
  const renderedUcids = useMemo(() => {
    if (ucids.length === 0) {
      return (
        <div className="p-8 text-center text-gray-500">
          <Target className="w-8 h-8 text-indigo-500/40 m-auto mb-2" />
          <p className="font-bold text-gray-400">
            No Active Mission Workflows
          </p>
          <p className="text-[10px] text-gray-600 mt-1 max-w-xs m-auto">
            Upload a Bill of Quantities workbook inside Ingestion Hub or
            use Solution Builder to spin up dual-sourcing cards.
          </p>
        </div>
      );
    }
    return ucids.map((u) => {
      const stepIdx = UCID_STEPS.findIndex(
        (s) => s.id === u.currentStep,
      );
      const pct = Math.round(
        (stepIdx / (UCID_STEPS.length - 1)) * 100,
      );
      const PRIORITY_COLOR: Record<string, string> = {
        critical: tokens.colors.status.error,
        high: tokens.colors.status.warning,
        medium: tokens.colors.accent.indigo,
        low: tokens.colors.text.muted,
      };
      return (
        <button
          key={u.id}
          onClick={() => onNavigate("mission-control")}
          className="w-full text-left px-4 py-3 hover:bg-white/[0.01] transition-colors cursor-pointer block"
        >
          <div className="flex items-center justify-between mb-1.5">
            <div className="flex items-center gap-2">
              <span
                className="w-1.5 h-1.5 rounded-full shrink-0"
                style={{ background: PRIORITY_COLOR[u.priority] }}
              />
              <span
                className="text-xs font-semibold"
                style={{ color: tokens.colors.text.primary }}
              >
                {u.displayId}
              </span>
              <span
                className="text-[10px] px-1.5 py-0.5 rounded-full capitalize"
                style={{
                  background: "rgba(74, 133, 253,0.1)",
                  color: tokens.colors.text.secondary,
                }}
              >
                {u.priority}
              </span>
            </div>
            <span
              className="text-[11px]"
              style={{
                color:
                  u.currentStep === "snapshot"
                    ? tokens.colors.status.success
                    : tokens.colors.status.warning,
              }}
            >
              {UCID_STEPS.find((s) => s.id === u.currentStep)
                ?.label || u.currentStep}
            </span>
          </div>
          <p
            className="text-[11px] mb-2 text-left"
            style={{ color: tokens.colors.text.muted }}
          >
            {u.name}
          </p>
          <div className="flex items-center gap-3">
            <div
              className="flex-1 h-1 rounded-full overflow-hidden"
              style={{ background: "rgba(74, 133, 253,0.1)" }}
            >
              <div
                className="h-full rounded-full transition-all duration-500"
                style={{
                  width: `${pct}%`,
                  background:
                    u.currentStep === "snapshot"
                      ? tokens.colors.status.success
                      : `linear-gradient(90deg, ${tokens.colors.accent.indigo}, ${tokens.colors.status.success})`,
                }}
              />
            </div>
            <span
              className="text-[10px] shrink-0"
              style={{ color: tokens.colors.text.tertiary }}
            >
              {pct}%
            </span>
          </div>
        </button>
      );
    });
  }, [ucids, onNavigate]);

  return (
    <ErrorBoundary>
      <motion.div 
        className="space-y-4"
        initial={{ y: 10, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.4, ease: "easeOut", staggerChildren: 0.1 }}
      >
        {/* Welcome banner */}
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ duration: 0.4, ease: "easeOut" }}
        className="rounded-xl p-4 flex items-center justify-between"
        style={{
          background:
            "linear-gradient(135deg, rgba(74, 133, 253,0.12) 0%, rgba(0,212,160,0.06) 100%)",
          border: "1px solid rgba(74, 133, 253,0.18)",
        }}
      >
        <div>
          <p
            className="text-base"
            style={{ color: tokens.colors.text.primary, fontWeight: 500 }} 
          >
            Procurement Intelligence Hub
          </p>
          <p className="text-sm mt-0.5" style={{ color: tokens.colors.text.muted }}> 
            {activeUCIDs.length} active UCIDs in pipeline · {connectedVendors}{" "}
            vendors live · {criticalIssues} critical issues awaiting review
          </p>
        </div>
        <div className="flex items-center gap-2">
          {criticalIssues > 0 && (
            <button
              onClick={() => onNavigate("forensic")}
              className="flex items-center gap-2 text-xs px-4 py-2 rounded-lg hover:opacity-90 transition-all cursor-pointer border border-status-error/30"
              style={{ background: tokens.colors.status.error, color: tokens.colors.text.primary }} 
            >
              <AlertTriangle className="w-3.5 h-3.5 animate-bounce" />
              Resolve {criticalIssues} Critical
            </button>
          )}
          <button
            onClick={() => onNavigate("mission-control")}
            className="flex items-center gap-2 text-xs px-4 py-2 rounded-lg hover:opacity-90 transition-all cursor-pointer"
            style={{ background: tokens.colors.accent.indigo, color: tokens.colors.text.primary }} 
          >
            <Target className="w-3.5 h-3.5" />
            Live Mission Control
          </button>
        </div>
      </motion.div>

      {/* KPI cards */}
      <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-6 gap-3">
        {KPI_CARDS.map((kpi, i) => (
          <KpiCard
            key={kpi.label + i}
            id={kpi.id}
            label={kpi.label}
            value={kpi.value}
            sub={kpi.sub}
            icon={kpi.icon}
            color={kpi.color}
            delta={kpi.delta}
            up={kpi.up}
            hovered={hovered === `kpi-${i}`}
            onMouseEnter={() => setHovered(`kpi-${i}`)}
            onMouseLeave={() => setHovered(null)}
            onClick={() => onNavigate(kpi.id as AppView)}
          />
        ))}
      </div>

      {/* Charts row */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* Catalog Growth */}
        <CatalogTrendAnalyzer
          dimensions={areaChart.dimensions}
          chartRef={areaChart.ref}
        />

        {/* Vendor SKU Distribution */}
        <VendorStatusBoard
          totalCatalog={totalCatalog}
          vendorPieData={VENDOR_PIE}
          dimensions={pieChart.dimensions}
          chartRef={pieChart.ref}
        />
      </div>

      {/* UCID Pipeline + Vendor Status */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* Active UCID Pipeline */}
        <div
          className="lg:col-span-2 rounded-xl overflow-hidden"
          style={{
            background: "var(--color-surface-elevated)",
            border: "1px solid rgba(74, 133, 253,0.1)",
          }}
        >
          <div
            className="flex items-center justify-between px-4 py-3 border-b"
            style={{ borderColor: "rgba(74, 133, 253,0.08)" }}
          >
            <p className="text-sm font-semibold" style={{ color: tokens.colors.text.primary }}> 
              UCID Mission Pipeline
            </p>
            <button
              onClick={() => onNavigate("mission-control")}
              className="flex items-center gap-1 text-xs text-brand-indigo hover:underline cursor-pointer"
            >
              Open Live Mission <ChevronRight className="w-3 h-3" />
            </button>
          </div>
          <div
            className="divide-y"
            style={{ borderColor: "rgba(74, 133, 253,0.06)" }}
          >
            {renderedUcids}
          </div>
        </div>

        {/* Vendor API Status + Issues */}
        <div className="space-y-4">
          <VendorHealthList vendors={vendors} onNavigate={onNavigate} />
          <ActiveIssuesList forensicIssues={forensicIssues} onNavigate={onNavigate} />
        </div>
      </div>
    </motion.div>
  </ErrorBoundary>
  );
}

import React, { useState, useEffect } from "react";
import { motion } from "motion/react";
import {
  ShieldAlert,
  CheckCircle,
  Search,
  Loader2,
  Plus,
  Trash2,
  Edit3,
  Save,
  X,
  BrainCircuit,
  Database,
  Sparkles,
  Info,
} from "lucide-react";
import type { ForensicIssue, Vendor, CatalogSKU, UCID, SourcingRule, LearningEvent, AppView } from "../../types";
import { apiClient } from "../../services/apiClient";
import { ForensicHeader } from "./ForensicHeader";
import { ScannerOutput } from "./ScannerOutput";
import { ForensicIssueCard } from "./ForensicIssueCard";
import { ForensicSidebar } from "./ForensicSidebar";
import { SourcingRulesVault } from "./SourcingRulesVault";
import { LearningLoopFeed } from "./LearningLoopFeed";
import { ErrorBoundary } from "../shared/ErrorBoundary";
import { useLocalStorageState } from "../../hooks/useLocalStorageState";
import { useToast } from "../shared/ToastContext";

const INITIAL_RULES: SourcingRule[] = [
  {
    id: "rule-1",
    ruleType: "substitution",
    partNumber: "815100-B21",
    mappedOutput: "P40424-B21",
    label: "Obsolete Intel Xeon 6130 replacements mapping to Gen11 Gold 6430",
    vendor: "HPE",
    status: "active",
    isAutoLearned: false,
  },
  {
    id: "rule-2",
    ruleType: "price_cap",
    partNumber: "400-BPSB",
    mappedOutput: "1190",
    label: "Locked premier contractual rate overcharge guard for Enterprise NVMe Read Intensive SSDs",
    vendor: "Dell",
    status: "active",
    isAutoLearned: false,
  },
  {
    id: "rule-3",
    ruleType: "symmetry",
    partNumber: "Memory",
    mappedOutput: "multiple_of_8",
    label: "Verify odd configuration lines check and rebalance into symmetric 8-channel modules",
    vendor: "Cisco",
    status: "active",
    isAutoLearned: false,
  },
];

interface ForensicViewProps {
  forensicIssues: ForensicIssue[];
  setForensicIssues: React.Dispatch<React.SetStateAction<ForensicIssue[]>>;
  setVendors: React.Dispatch<React.SetStateAction<Vendor[]>>;
  setCatalogSkus: React.Dispatch<React.SetStateAction<CatalogSKU[]>>;
  ucids: UCID[];
  setUcids: React.Dispatch<React.SetStateAction<UCID[]>>;
  activeMissionId?: string;
  setActiveMissionId: React.Dispatch<React.SetStateAction<string | undefined>>;
  onNavigate?: (view: AppView) => void;
}

export function ForensicView({
  forensicIssues,
  setForensicIssues,
  setVendors,
  setCatalogSkus,
  ucids,
  setUcids,
  activeMissionId,
  setActiveMissionId,
  onNavigate,
}: ForensicViewProps) {
  const [scanning, setScanning] = useState(false);
  const [scanStdout, setScanStdout] = useState<string[]>([]);
  const [lastScanCount, setLastScanCount] = useState<number | null>(null);
  const { toast } = useToast();
  // Persistence dataset of sourcing policies
  const [sourcingRules, setSourcingRules] = useLocalStorageState<SourcingRule[]>(
    "sys_sourcing_intel_rules",
    INITIAL_RULES
  );

  const [prefillRule, setPrefillRule] = useState<Partial<SourcingRule> | null>(null);

  // Persisted learning events — the visible intelligence feed
  const [learningEvents, setLearningEvents] = useLocalStorageState<LearningEvent[]>(
    "sys_learning_events",
    []
  );

  // Helper: emit a learning event and tag the corresponding rule as auto-learned
  function emitLearningEvent(
    issueId: string,
    ruleType: LearningEvent["ruleType"],
    partNumber: string,
    action: string,
    vendor: string,
    confidenceScore: number
  ) {
    const eventId = `learn-${Date.now()}`;
    const newEvent: LearningEvent = {
      id: eventId,
      timestamp: new Date().toISOString(),
      sourceIssueId: issueId,
      ruleType,
      partNumber,
      action,
      confidenceScore,
      vendor,
      preventedMismatchCount: Math.floor(Math.random() * 4) + 1, // starts at 1-4, increments over time
    };
    setLearningEvents((prev) => [newEvent, ...prev].slice(0, 50));
  }

  // Get active selected profile or default to first
  const currUcid = ucids.find((u) => u.id === activeMissionId) || ucids[0];

  // --- Dynamic Contract Rule Scans ---
  const { hasEolSourcingRisk, hasPriceVarianceRisk, hasCiscoMemorySymmetryRisk } = React.useMemo(() => {
    return {
      hasEolSourcingRisk: currUcid?.solutions?.some((sol) =>
        sol.vendorSubmissions?.some((vs) =>
          vs.configs?.some((c) => c.items?.some((it) => it.partNumber === "815100-B21"),),
        ),
      ) || false,
      hasPriceVarianceRisk: currUcid?.solutions?.some((sol) =>
        sol.vendorSubmissions?.some((vs) =>
          vs.configs?.some((c) =>
            c.items?.some((it) => it.partNumber === "400-BPSB" && it.unitPrice > 1190,),
          ),
        ),
      ) || false,
      hasCiscoMemorySymmetryRisk: currUcid?.solutions?.some((sol) =>
        sol.vendorSubmissions?.some((vs) =>
            vs.vendor === "Cisco" &&
            vs.configs?.some((c) =>
              c.items?.some((it) => it.type === "Memory" && it.quantity % 8 !== 0,),
            ),
        ),
      ) || false
    };
  }, [currUcid]);

  // Build current open issues array derived directly from global forensicIssues prop and context-aware UCID constraints
  const openIssues = React.useMemo<ForensicIssue[]>(() => {
    return forensicIssues
      .filter((issue) => issue.status === "open" || !issue.status)
      .filter((issue) => {
        if (issue.id === "iss-1") return hasEolSourcingRisk;
        if (issue.id === "iss-2") return hasPriceVarianceRisk;
        if (issue.id === "iss-3") return hasCiscoMemorySymmetryRisk;
        if (issue.id === "iss-4") return true;
        return true;
      })
      .map((issue) => {
        // Dynamically enrich information from selected UCID configurations where appropriate
        if (issue.id === "iss-2" && hasPriceVarianceRisk) {
          const matchingSol = currUcid?.solutions?.find((sol) =>
            sol.vendorSubmissions?.some((vs) =>
              vs.configs?.some((c) => c.items?.some((it) => it.partNumber === "400-BPSB" && it.unitPrice > 1190,),),
            ),
          );
          const matchingVs = matchingSol?.vendorSubmissions?.find((vs) =>
            vs.configs?.some((c) => c.items?.some((it) => it.partNumber === "400-BPSB"),),
          );
          const matchingItem = matchingVs?.configs
            ?.flatMap((c) => c.items)
            .find((it) => it.partNumber === "400-BPSB");
          const unitPrice = matchingItem?.unitPrice || 1590;
          const overage = unitPrice - 1190;
          const totalWaste = overage * (matchingItem?.quantity || 24);
          return {
            ...issue,
            description: `Active quote for Dell 3.84TB drive (400-BPSB) is logged inside sheet as $${unitPrice.toLocaleString()}/ea. Direct API partner contract rate is $1,190. Overage mark-up: $${overage}/ea.`,
            affectedItems: matchingItem?.quantity || 24,
            suggestedAction: `Auto-Align local quote unit price to $1,190 negotiated rate. Saves $${totalWaste.toLocaleString()} instantly across lines.`,
          };
        }
        if (issue.id === "iss-3" && hasCiscoMemorySymmetryRisk) {
          const matchingSol = currUcid?.solutions?.find((sol) =>
            sol.vendorSubmissions?.some((vs) => vs.vendor === "Cisco"),
          );
          const matchingVs = matchingSol?.vendorSubmissions?.find(
            (vs) => vs.vendor === "Cisco",
          );

          const matchingItem = matchingVs?.configs
            ?.flatMap((c) => c.items)
            .find((it) => it.type === "Memory");
          const qty = matchingItem?.quantity || 5;
          return {
            ...issue,
            description: `Cisco UCS standard C240 configuration requests ${qty} memory modules. Intel Xeon 4th-Gen memory controllers operate optimally on 8-channel layouts. Odd allocation modules cause layout bus bottlenecks.`,
            affectedItems: qty,
            suggestedAction:
              "Upgrade configuration load to 8 units of 64GB DDR5 memory modules to satisfy full 8-channel Motherboard performance symmetry.",
          };
        }
        return issue;
      });
  }, [forensicIssues, hasEolSourcingRisk, hasPriceVarianceRisk, hasCiscoMemorySymmetryRisk, currUcid]);

  if (ucids.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center text-center p-12 bg-surface-elevated border border-white/5 rounded-xl gap-4 animate-fadeIn my-auto max-w-2xl mx-auto mt-12">
        <div className="w-16 h-16 rounded-full bg-indigo-500/10 flex items-center justify-center border border-indigo-500/20 text-indigo-400">
          <ShieldAlert className="w-8 h-8" />
        </div>
        <div className="space-y-1">
          <h2 className="text-sm font-semibold text-white">
            No Active Sourcing Profiles (UCIDs) Found
          </h2>
          <p className="text-xs text-gray-400 max-w-sm leading-normal">
            Your workspace data cache is current empty. Please go to the Ingest
            Hub to upload a sourcing workbook or use the compile desk to build
            your first tracking context.
          </p>
        </div>
        <button
          onClick={() => onNavigate?.("ingestion-hub")}
          className="px-5 py-2.5 rounded-lg bg-indigo-500 hover:bg-indigo-600 text-white font-bold cursor-pointer transition text-xs border-0 focus:outline-none shadow-lg shadow-indigo-500/15"
        >
          Go to Ingestion Hub
        </button>
      </div>
    );
  }

  // Helper trigger feedback
  function triggerToast(message: string, type: "success" | "warn" | "error" = "success") {
    toast(message, type);
  }

  async function runAuditScanner() {
    setScanning(true);
    setScanStdout([
      "Booting VSIP forensic diagnostic sweep engine...",
      `Connecting active configuration workspace profile [${currUcid?.displayId || "UNKNOWN"}]`,
    ]);

    try {
      await apiClient.post("/api/jobs", {
        type: "forensics",
        context: { ucid: currUcid?.id || "mock-ucid", config_id: "all", solution_id: "all" },
        parent_job_id: ""
      });

      const lines = [
        `Validating structural Bill of Materials nodes under profile ${currUcid?.displayId}...`,
        "Interrogating direct HPE REST quotation endpoints...",
        "Comparing Dell Premier partner contract pricing databases...",
        "Auditing Cisco unified socket bus configuration symmetry requirements...",
        "Analyzing multi-sheet compliance rules validations...",
      ];

      for (const line of lines) {
        setScanStdout((prev) => [...prev, line]);
      }

      setScanning(false);
      setLastScanCount(openIssues.length);
      triggerToast(
        "Diagnostic scan complete! Sourcing sheet analyzed successfully.",
        "success",
      );
    } catch (err) {
      setScanning(false);
      triggerToast("Diagnostic scan failed.", "error");
    }
  }

  // High performance direct correction script mapping to state
  function handleAutoHeal(issueId: string) {
    if (!currUcid) return;

    if (issueId === "iss-1") {
      // HPE EOL repair script - replace obsolete legacy CPU with Xeon Gold 6430
      setUcids((prev) =>
        prev.map((u) => {
          if (u.id === currUcid.id) {
            const nextSolutions = u.solutions.map((sol) => {
              const matchedCPU = sol.vendorSubmissions?.some((vs) =>
                vs.configs?.some((c) =>
                  c.items?.some((it) => it.partNumber === "815100-B21"),
                ),
              );
              if (!matchedCPU) return sol;

              const repairedSubmissions =
                sol.vendorSubmissions?.map((vs) => {
                  const repairedConfigs =
                    vs.configs?.map((c) => {
                      const repairedItems =
                        c.items?.map((it) => {
                          if (it.partNumber === "815100-B21") {
                            return {
                              ...it,
                              partNumber: "P40424-B21",
                              name: "Intel Xeon Gold 6430 32-Core 2.1GHz Processor (Gen11) [REPLACED]",
                              unitPrice: 2150,
                            };
                          }
                          return it;
                        }) || [];
                      const newConfigSum = repairedItems.reduce(
                        (acc, curr) => acc + curr.unitPrice * curr.quantity,
                        0,
                      );
                      return {
                        ...c,
                        items: repairedItems,
                        totalPrice: newConfigSum,
                        savings: Math.max(0, c.originalPrice - newConfigSum),
                      };
                    }) || [];
                  const newVsSum = repairedConfigs.reduce(
                    (acc, c) => acc + c.totalPrice,
                    0,
                  );
                  return {
                    ...vs,
                    configs: repairedConfigs,
                    totalPrice: newVsSum,
                    savings: Math.max(0, vs.originalPrice - newVsSum),
                    complianceScore: 100,
                  };
                }) || [];

              return {
                ...sol,
                vendorSubmissions: repairedSubmissions,
              };
            });

            return {
              ...u,
              solutions: nextSolutions,
              events: [
                ...u.events,
                {
                  ts: new Date().toLocaleTimeString(),
                  level: "ok",
                  msg: "Forensic System Repair: Replaced obsolete legacy HPE CPU (815100-B21) with supported factory Intel Gold 6430 (P40424-B21). Sourcing lead-time risks eliminated.",
                },
              ],
            };
          }
          return u;
        }),
      );

      setForensicIssues?.((prev) =>
        prev.map((iss) =>
          iss.id === "iss-1" ? { ...iss, status: "resolved" as const } : iss,
        ),
      );

      triggerToast("HPE Obsolete CPU constraint successfully resolved and signed.", "success");

      // --- CENTRAL CATALOG SYNC (Learning Loop Feed) ---
      // Update the status of the obsolete part in the Master Catalog to prevent future obsolete matches, and designate P40424-B21 as optimal
      setCatalogSkus((prev) =>
        prev.map((sku) => {
          if (sku.partNumber === "815100-B21") {
            return {
              ...sku,
              status: "eol" as const,
              name: "Intel Xeon Gold 6130 16-Core (Legacy Gen10) - EOL [REPLACED BY P40424-B21]",
            };
          }
          if (sku.partNumber === "P40424-B21") {
            return {
              ...sku,
              name: "Intel Xeon Gold 6430 32-Core 2.1GHz Processor (Gen11) [ACTIVE REPLACEMENT]",
            };
          }
          return sku;
        })
      );

      // Auto-feed the intelligence override policy database
      setSourcingRules((prev) => {
        const exists = prev.some((r) => r.partNumber === "815100-B21");
        if (exists) return prev;
        const newLearned: SourcingRule = {
          id: `rule-${Date.now()}-eol`,
          ruleType: "substitution",
          partNumber: "815100-B21",
          mappedOutput: "P40424-B21",
          label: "Auto-Learned: Obsolete HPE CPU mapped to high compliance Intel Gold 6430",
          vendor: "HPE",
          status: "active",
          learnedAt: new Date().toISOString(),
          sourceIssueId: "iss-1",
          isAutoLearned: true,
          preventedMismatchCount: 1,
        };
        return [newLearned, ...prev];
      });

      // Emit learning event for the feed
      emitLearningEvent(
        "iss-1",
        "substitution",
        "815100-B21",
        "Obsolete HPE Intel Xeon Gold 6130 CPU (815100-B21) auto-substituted to Gen11 Gold 6430 (P40424-B21). Sourcing lead-time risk eliminated and catalog EOL status updated.",
        "HPE",
        96
      );

      triggerToast(
        "HPE EOL CPU replaced & catalog replacement rule populated!",
        "success",
      );
    }

    if (issueId === "iss-2") {
      // Dell Price aligner - change 1590 overcharge back to 1190 contractor contract rate
      setUcids((prev) =>
        prev.map((u) => {
          if (u.id === currUcid.id) {
            const nextSolutions = u.solutions.map((sol) => {
              const hasOverage = sol.vendorSubmissions?.some((vs) =>
                vs.configs?.some((c) =>
                  c.items?.some(
                    (it) => it.partNumber === "400-BPSB" && it.unitPrice > 1190,
                  ),
                ),
              );
              if (!hasOverage) return sol;

              const repairedSubmissions =
                sol.vendorSubmissions?.map((vs) => {
                  const repairedConfigs =
                    vs.configs?.map((c) => {
                      const repairedItems =
                        c.items?.map((it) => {
                          if (it.partNumber === "400-BPSB") {
                            return {
                              ...it,
                              unitPrice: 1190,
                              name: "Dell 3.84TB Enterprise NVMe SSD SFF [ALIGNED]",
                            };
                          }
                          return it;
                        }) || [];
                      const newConfigSum = repairedItems.reduce(
                        (acc, curr) => acc + curr.unitPrice * curr.quantity,
                        0,
                      );
                      return {
                        ...c,
                        items: repairedItems,
                        totalPrice: newConfigSum,
                        savings: Math.max(0, c.originalPrice - newConfigSum),
                      };
                    }) || [];
                  const newVsSum = repairedConfigs.reduce(
                    (acc, c) => acc + c.totalPrice,
                    0,
                  );
                  return {
                    ...vs,
                    configs: repairedConfigs,
                    totalPrice: newVsSum,
                    savings: Math.max(0, vs.originalPrice - newVsSum),
                  };
                }) || [];

              return {
                ...sol,
                vendorSubmissions: repairedSubmissions,
              };
            });

            return {
              ...u,
              solutions: nextSolutions,
              events: [
                ...u.events,
                {
                  ts: new Date().toLocaleTimeString(),
                  level: "ok",
                  msg: "Forensic System Repair: Corrected Dell Premier Drive mark-up overcharge. Aligned unit pricing to matched API partner contract rate of $1,190.",
                },
              ],
            };
          }
          return u;
        }),
      );

      setForensicIssues?.((prev) =>
        prev.map((iss) =>
          iss.id === "iss-2" ? { ...iss, status: "resolved" as const } : iss,
        ),
      );

      // --- CENTRAL CATALOG SYNC (Learning Loop Feed) ---
      // Lock the verified contractor rate of $1,190 inside the Master inventory to pre-empt future markups
      setCatalogSkus((prev) =>
        prev.map((sku) => {
          if (sku.partNumber === "400-BPSB") {
            return {
              ...sku,
              price: 1190,
              name: "Dell 3.84TB Enterprise NVMe Read Intensive SSD SFF [CONTRACT LOCKED]",
              status: "active" as const,
            };
          }
          return sku;
        })
      );

      // Auto-feed the intelligence override policy database
      setSourcingRules((prev) => {
        const exists = prev.some((r) => r.partNumber === "400-BPSB" && r.ruleType === "price_cap");
        if (exists) return prev;
        const newLearned: SourcingRule = {
          id: `rule-${Date.now()}-price`,
          ruleType: "price_cap",
          partNumber: "400-BPSB",
          mappedOutput: "1190",
          label: "Auto-Learned: Contract target Cap rate overcharge protection locked at $1,190",
          vendor: "Dell",
          status: "active",
          learnedAt: new Date().toISOString(),
          sourceIssueId: "iss-2",
          isAutoLearned: true,
          preventedMismatchCount: 1,
        };
        return [newLearned, ...prev];
      });

      // Emit learning event for the feed
      emitLearningEvent(
        "iss-2",
        "price_cap",
        "400-BPSB",
        "Dell Premier portal markup detected: 400-BPSB quoted at $1,590 vs contract rate $1,190. Price cap rule locked to prevent future overcharge. Saves $9,600 across 24 units.",
        "Dell",
        99
      );

      triggerToast(
        "Dell Quote pricing aligned & catalog contract price verified!",
        "success",
      );
    }

    if (issueId === "iss-3") {
      // Cisco Memory symmetric upgrade - set quantity to 8 to balance Xeon gold dual bus layout optimally
      setUcids((prev) =>
        prev.map((u) => {
          if (u.id === currUcid.id) {
            const nextSolutions = u.solutions.map((sol) => {
              const hasAsymmetricMemory = sol.vendorSubmissions?.some(
                (vs) =>
                  vs.vendor === "Cisco" &&
                  vs.configs?.some((c) =>
                    c.items?.some(
                      (it) => it.type === "Memory" && it.quantity % 8 !== 0,
                    ),
                  ),
              );
              if (!hasAsymmetricMemory) return sol;

              const repairedSubmissions =
                sol.vendorSubmissions?.map((vs) => {
                  if (vs.vendor !== "Cisco") return vs;
                  const repairedConfigs =
                    vs.configs?.map((c) => {
                      const repairedItems =
                        c.items?.map((it) => {
                          if (it.type === "Memory") {
                            return {
                              ...it,
                              quantity: 8,
                              name: "Cisco 64GB DDR5 memory module [REBALANCED]",
                            };
                          }
                          return it;
                        }) || [];
                      const newConfigSum = repairedItems.reduce(
                        (acc, curr) => acc + curr.unitPrice * curr.quantity,
                        0,
                      );
                      return {
                        ...c,
                        items: repairedItems,
                        totalPrice: newConfigSum,
                        savings: Math.max(0, c.originalPrice - newConfigSum),
                      };
                    }) || [];
                  const newVsSum = repairedConfigs.reduce(
                    (acc, c) => acc + c.totalPrice,
                    0,
                  );
                  return {
                    ...vs,
                    configs: repairedConfigs,
                    totalPrice: newVsSum,
                    savings: Math.max(0, vs.originalPrice - newVsSum),
                  };
                }) || [];

              return {
                ...sol,
                vendorSubmissions: repairedSubmissions,
              };
            });

            return {
              ...u,
              solutions: nextSolutions,
              events: [
                ...u.events,
                {
                  ts: new Date().toLocaleTimeString(),
                  level: "ok",
                  msg: "Forensic System Repair: Balanced Cisco memory distribution to 8 dual-rank modules. Re-established symmetric motherboard 8-channel indexing.",
                },
              ],
            };
          }
          return u;
        }),
      );

      setForensicIssues?.((prev) =>
        prev.map((iss) =>
          iss.id === "iss-3" ? { ...iss, status: "resolved" as const } : iss,
        ),
      );

      // --- CENTRAL CATALOG SYNC (Learning Loop Feed) ---
      // Update taxonomy guidelines associated with Cisco memory SKUs in the catalog
      setCatalogSkus((prev) =>
        prev.map((sku) => {
          if (sku.vendor === "Cisco" && sku.type === "Memory") {
            return {
              ...sku,
              name: sku.name.includes("[SYMMETRY_VERIFIED]") ? sku.name : `${sku.name} [SYMMETRY_VERIFIED]`,
            };
          }
          return sku;
        })
      );

      // Auto-feed the intelligence override policy database
      setSourcingRules((prev) => {
        const exists = prev.some((r) => r.partNumber === "Memory" && r.vendor === "Cisco");
        if (exists) return prev;
        const newLearned: SourcingRule = {
          id: `rule-${Date.now()}-sym`,
          ruleType: "symmetry",
          partNumber: "Memory",
          mappedOutput: "multiple_of_8",
          label: "Auto-Learned: Cisco UCS memory rebalanced to 8-channel socket layout symmetry",
          vendor: "Cisco",
          status: "active",
          learnedAt: new Date().toISOString(),
          sourceIssueId: "iss-3",
          isAutoLearned: true,
          preventedMismatchCount: 1,
        };
        return [newLearned, ...prev];
      });

      // Emit learning event for the feed
      emitLearningEvent(
        "iss-3",
        "symmetry",
        "Memory",
        "Cisco UCS C240 M7 memory asymmetry detected (5 modules). Auto-rebalanced to 8-channel DDR5 layout. Intel Xeon 4th-Gen bus bottleneck eliminated. Symmetry rule persisted for future Cisco BOM scans.",
        "Cisco",
        91
      );

      triggerToast(
        "Cisco memory layout load-balanced for optimal motherboard symmetry!",
        "success",
      );
    }

    if (issueId === "iss-4") {
      // Auto-heal Juniper - authorize connected API credentials
      setVendors((prev) =>
        prev.map((v) =>
          v.shortName === "Juniper"
            ? { ...v, status: "connected", apiHealth: 100 }
            : v,
        ),
      );

      // Auto-feed the intelligence override policy database
      setSourcingRules((prev) => {
        const exists = prev.some((r) => r.partNumber === "Juniper API" && r.vendor === "Juniper");
        if (exists) return prev;
        const newLearned: SourcingRule = {
          id: `rule-${Date.now()}-api`,
          ruleType: "api_gateway",
          partNumber: "Juniper API",
          mappedOutput: "authorized_oauth_v1",
          label: "Auto-Learned: Restored security tokens and partner gateway synchronization",
          vendor: "Juniper",
          status: "active",
          learnedAt: new Date().toISOString(),
          sourceIssueId: "iss-4",
          isAutoLearned: true,
          preventedMismatchCount: 1,
        };
        return [newLearned, ...prev];
      });

      // Emit learning event for the feed
      emitLearningEvent(
        "iss-4",
        "api_gateway",
        "Juniper API",
        "Juniper Networks partner API OAuth token expired. Credentials re-authorized, vendor connection restored to 100% health. API gateway rule persisted to prevent future outages.",
        "Juniper",
        88
      );

      setForensicIssues((prev) =>
        prev.map((iss) =>
          iss.id === "iss-4" ? { ...iss, status: "resolved" as const } : iss,
        ),
      );
      triggerToast(
        "Juniper Networks partner API connected and authorized!",
        "success",
      );
    }
  }

  const handleManualPromote = (issue: ForensicIssue) => {
    if (issue.id === "iss-1") {
      setPrefillRule({
        ruleType: "substitution",
        partNumber: "815100-B21",
        mappedOutput: "P40424-B21",
        vendor: "HPE",
        label: "Manual Override: Map obsolete 815100-B21 to P40424-B21 CPU"
      });
    } else if (issue.id === "iss-2") {
      setPrefillRule({
        ruleType: "price_cap",
        partNumber: "400-BPSB",
        mappedOutput: "1190",
        vendor: "Dell",
        label: "Manual Override: Cap Dell 400-BPSB at contract level of $1,190"
      });
    } else if (issue.id === "iss-3") {
      setPrefillRule({
        ruleType: "symmetry",
        partNumber: "Memory",
        mappedOutput: "multiple_of_8",
        vendor: "Cisco",
        label: "Manual Override: Enforce memory socket physical layout symmetry multi-of-8"
      });
    } else if (issue.id === "iss-4") {
      setPrefillRule({
        ruleType: "api_gateway",
        partNumber: "Juniper API",
        mappedOutput: "authorized_oauth_v1",
        vendor: "Juniper",
        label: "Manual Override: Authorize active telemetry pipeline credentials"
      });
    }
  };

  return (
    <ErrorBoundary>
      <motion.div 
        className="flex flex-col gap-4"
        initial={{ opacity: 0, y: 15 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4, ease: "easeOut", staggerChildren: 0.1 }}
      >

      <ForensicHeader
        currUcid={currUcid}
        ucids={ucids}
        scanning={scanning}
        setActiveMissionId={setActiveMissionId}
        runAuditScanner={runAuditScanner}
      />

      <ScannerOutput scanning={scanning} scanStdout={scanStdout} />

      {/* Warnings & Issues split */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* Main List */}
        <div className="lg:col-span-2 flex flex-col gap-3">
          <div className="flex items-center justify-between px-1 shrink-0">
            <span className="text-xs text-gray-400 font-semibold uppercase tracking-wider">
              Discovered Sourcing Anomalies ({openIssues.length})
            </span>
            {lastScanCount !== null && (
              <span className="text-[10px] text-gray-500 font-mono">
                Last diagnosis sweep scan matching: {lastScanCount} rules
              </span>
            )}
          </div>

          <div className="pr-1 space-y-3">
            {openIssues.length > 0 ? (
              openIssues.map((issue) => (
                <ForensicIssueCard
                  key={issue.id}
                  issue={issue}
                  onAutoHeal={handleAutoHeal}
                  onManualPromote={handleManualPromote}
                />
              ))
            ) : (
              <div className="p-12 rounded-xl border border-dashed border-gray-800 bg-black/20 flex flex-col items-center justify-center gap-2 text-center h-full">
                <div className="w-16 h-16 rounded-full bg-status-success/10 flex items-center justify-center mb-2 border border-status-success/20">
                  <Search className="w-8 h-8 text-status-success" />
                </div>
                <h3 className="text-xl font-bold text-content-primary mb-1">
                  Audit Trail Clean
                </h3>
                <p className="text-sm text-content-muted max-w-sm">
                  No forensic anomalies or compliance violations detected.
                </p>
              </div>
            )}
          </div>
        </div>

        {/* Audit reports sidebar */}
          <ForensicSidebar
            openIssuesCount={openIssues.length}
            forensicIssues={forensicIssues}
          />
        </div>

      {/* Sourcing Intelligence Policy Rules Vault */}
      <SourcingRulesVault
        sourcingRules={sourcingRules}
        setSourcingRules={setSourcingRules}
        triggerToast={triggerToast}
        prefillRule={prefillRule}
        onPrefillConsumed={() => setPrefillRule(null)}
      />

      {/* Intelligence Learning Loop Feed — visible telemetry of everything the system has learned */}
      <LearningLoopFeed
        learningEvents={learningEvents}
        activeRuleCount={sourcingRules.filter((r) => r.status === "active").length}
        onMarkReviewed={(eventId) => {
          setLearningEvents((prev) => prev.filter((e) => e.id !== eventId));
          triggerToast("Learning event acknowledged and archived.", "success");
        }}
      />
    </motion.div>
  </ErrorBoundary>
  );
}

import React, { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "motion/react";
import { BrainCircuit, X, Send, Sparkles, AlertCircle, CheckCircle2, Loader2, ArrowRight } from "lucide-react";
import type { SourcingRule } from "../../types";

interface LearningLoopInjectorProps {
  onRuleDrafted: (rule: SourcingRule) => void;
  onClose: () => void;
}

type InjectorState = "idle" | "parsing" | "clarifying_target" | "clarifying_scope" | "drafting";

interface ChatMessage {
  id: string;
  sender: "human" | "agent";
  text: string;
  isActionable?: boolean;
}

export function LearningLoopInjector({ onRuleDrafted, onClose }: LearningLoopInjectorProps) {
  const [state, setState] = useState<InjectorState>("idle");
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: "init",
      sender: "agent",
      text: "I am ready to learn. Describe the intelligence rule or hardware constraint you want to add.",
    }
  ]);
  const [inputValue, setInputValue] = useState("");
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Temporary storage for parsed semantic intent
  const [parsedIntent, setParsedIntent] = useState<Partial<SourcingRule>>({});

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const analyzeInitialInput = (text: string) => {
    const lower = text.toLowerCase();

    // Mock NLP Parser Logic
    let ruleType: SourcingRule["ruleType"] = "substitution";
    if (lower.includes("symmetry") || lower.includes("balance") || lower.includes("memory") || lower.includes("require")) {
      ruleType = "symmetry";
    } else if (lower.includes("cap") || lower.includes("price") || lower.includes("$")) {
      ruleType = "price_cap";
    }

    setParsedIntent({
      ruleType,
      label: text, // Use the raw description as the narrative
      vendor: lower.includes("cisco") ? "Cisco" : lower.includes("dell") ? "Dell" : "HPE"
    });

    setState("clarifying_target");
    setMessages(prev => [
      ...prev,
      {
        id: Date.now().toString(),
        sender: "agent",
        text: `I've mapped this as a "${ruleType.toUpperCase()}" rule for ${lower.includes("cisco") ? "Cisco" : lower.includes("dell") ? "Dell" : "HPE"}. However, I need the exact target parameter this applies to (e.g., "Memory", "P40424-B21", or "All Chassis"). What should I target?`,
        isActionable: true,
      }
    ]);
  };

  const finalizeRule = (scopeText: string) => {
    const rule: SourcingRule = {
      id: "rule-draft-" + Date.now(),
      ruleType: parsedIntent.ruleType || "substitution",
      partNumber: `${parsedIntent.partNumber} [Scope: ${scopeText}]`,
      mappedOutput: "SYMMETRY_ENFORCED", // Mock mapped output for now
      label: parsedIntent.label || "Auto-learned rule",
      vendor: parsedIntent.vendor || "HPE",
      status: "draft",
      isAutoLearned: true,
      learnedAt: new Date().toISOString(),
    };

    if (rule.ruleType === "price_cap") rule.mappedOutput = "5000";

    setState("drafting");
    setMessages(prev => [
      ...prev,
      {
        id: Date.now().toString(),
        sender: "agent",
        text: `Perfect. I've successfully mapped the intelligence with strict boundaries to prevent it from bleeding into other areas. Generating draft rule for quarantine...`,
      }
    ]);

    setTimeout(() => {
      onRuleDrafted(rule);
    }, 1500);
  };

  const handleSend = () => {
    if (!inputValue.trim() || state === "parsing" || state === "drafting") return;

    const userText = inputValue.trim();
    setMessages(prev => [...prev, { id: Date.now().toString(), sender: "human", text: userText }]);
    setInputValue("");

    if (state === "idle") {
      setState("parsing");
      setTimeout(() => analyzeInitialInput(userText), 1500);
    } else if (state === "clarifying_target") {
      setParsedIntent(prev => ({ ...prev, partNumber: userText }));
      setState("parsing");
      setTimeout(() => {
        setState("clarifying_scope");
        setMessages(prev => [
          ...prev,
          {
            id: Date.now().toString(),
            sender: "agent",
            text: `Got it. Target is set to "${userText}". Finally, to prevent spamming irrelevant items, what is the strict scope level for this rule? (e.g. "Global Brand", "Specific Category Only", "Exact SKU Match Only")`,
            isActionable: true,
          }
        ]);
      }, 1000);
    } else if (state === "clarifying_scope") {
      setState("parsing");
      setTimeout(() => finalizeRule(userText), 1200);
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0, height: 0, y: -10 }}
      animate={{ opacity: 1, height: "auto", y: 0 }}
      exit={{ opacity: 0, height: 0, scale: 0.95 }}
      className="rounded-xl border bg-black/40 overflow-hidden mb-4 flex flex-col"
      style={{ borderColor: "rgba(74, 133, 253, 0.3)" }}
    >
      {/* Header */}
      <div className="flex items-center justify-between p-3 border-b border-indigo-500/20 bg-indigo-500/10">
        <div className="flex items-center gap-2">
          <Sparkles className="w-4 h-4 text-indigo-400 animate-pulse" />
          <h4 className="text-xs font-bold text-indigo-100 uppercase tracking-wider font-mono">
            Semantic Intelligence Injector
          </h4>
        </div>
        <button onClick={onClose} className="text-gray-400 hover:text-white transition cursor-pointer">
          <X className="w-4 h-4" />
        </button>
      </div>

      {/* Chat Area */}
      <div className="p-4 flex flex-col gap-3 max-h-[300px] overflow-y-auto">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.sender === "human" ? "justify-end" : "justify-start"}`}>
            <div className={`max-w-[80%] rounded-lg p-3 text-xs leading-relaxed ${
              msg.sender === "human" 
                ? "bg-indigo-500/20 border border-indigo-500/30 text-indigo-100 rounded-br-sm" 
                : "bg-white/5 border border-white/10 text-gray-300 rounded-bl-sm"
            }`}>
              {msg.sender === "agent" && (
                <div className="flex items-center gap-1.5 mb-1.5 text-[9px] font-bold text-indigo-400 uppercase tracking-wider">
                  <BrainCircuit className="w-3 h-3" /> Agent
                </div>
              )}
              {msg.text}
            </div>
          </div>
        ))}

        {state === "parsing" && (
          <div className="flex justify-start">
            <div className="max-w-[80%] rounded-lg p-3 bg-white/5 border border-white/10 text-gray-400 rounded-bl-sm flex items-center gap-2 text-xs">
              <Loader2 className="w-3.5 h-3.5 animate-spin text-indigo-400" />
              Parsing semantic intent...
            </div>
          </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-3 border-t border-white/5 bg-black/50 flex items-center gap-2">
        <input 
          type="text"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          placeholder={state.includes("clarifying") ? "Type the missing parameter..." : "Describe the intelligence..."}
          disabled={state === "parsing" || state === "drafting"}
          className="flex-1 bg-white/5 border border-white/10 rounded-lg px-3 py-2 text-xs text-white placeholder-gray-500 focus:outline-none focus:border-indigo-500/50 disabled:opacity-50"
        />
        <button 
          onClick={handleSend}
          disabled={!inputValue.trim() || state === "parsing" || state === "drafting"}
          className="p-2 rounded-lg bg-indigo-500 hover:bg-indigo-600 disabled:bg-gray-700 disabled:text-gray-500 text-white transition cursor-pointer"
        >
          <Send className="w-4 h-4" />
        </button>
      </div>
    </motion.div>
  );
}

