import { tokens } from "../../styles/tokens";
import React, { useState, useEffect } from "react";
import { BrainCircuit, X, Plus, Info, Sparkles, Save, Trash2, Edit3, Loader2, Activity } from "lucide-react";
import { motion, AnimatePresence } from "motion/react";
import type { SourcingRule } from "../../types";
import { apiClient } from "../../services/apiClient";
import { LearningLoopInjector } from "./LearningLoopInjector";

interface SourcingRulesVaultProps {
  sourcingRules: SourcingRule[];
  setSourcingRules: React.Dispatch<React.SetStateAction<SourcingRule[]>>;
  triggerToast: (message: string, type: "success" | "warn") => void;
  prefillRule: Partial<SourcingRule> | null;
  onPrefillConsumed: () => void;
}

export function SourcingRulesVault({
  sourcingRules,
  setSourcingRules,
  triggerToast,
  prefillRule,
  onPrefillConsumed,
}: SourcingRulesVaultProps) {
  const [isAddingRule, setIsAddingRule] = useState(false);
  const [isInjectingIntel, setIsInjectingIntel] = useState(false);
  const [simulatingRuleId, setSimulatingRuleId] = useState<string | null>(null);

  const [newRuleType, setNewRuleType] = useState<SourcingRule["ruleType"]>("substitution");
  const [newPartNumber, setNewPartNumber] = useState("");
  const [newMappedOutput, setNewMappedOutput] = useState("");
  const [newLabel, setNewLabel] = useState("");
  const [newVendor, setNewVendor] = useState("HPE");
  const [newStatus, setNewStatus] = useState<SourcingRule["status"]>("active");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [editingRuleId, setEditingRuleId] = useState<string | null>(null);
  const [editPartNumber, setEditPartNumber] = useState("");
  const [editMappedOutput, setEditMappedOutput] = useState("");
  const [editLabel, setEditLabel] = useState("");
  const [editVendor, setEditVendor] = useState("");
  const [editStatus, setEditStatus] = useState<SourcingRule["status"]>("active");

  useEffect(() => {
    if (prefillRule) {
      setIsAddingRule(true);
      if (prefillRule.ruleType) setNewRuleType(prefillRule.ruleType);
      if (prefillRule.partNumber) setNewPartNumber(prefillRule.partNumber);
      if (prefillRule.mappedOutput) setNewMappedOutput(prefillRule.mappedOutput);
      if (prefillRule.label) setNewLabel(prefillRule.label);
      if (prefillRule.vendor) setNewVendor(prefillRule.vendor);
      setNewStatus("active");
      onPrefillConsumed();

      triggerToast("Override parameters prefilled! Review and save the rule at the bottom.", "success");
      setTimeout(() => {
        document.querySelector("form")?.scrollIntoView({ behavior: "smooth" });
      }, 150);
    }
  }, [prefillRule, onPrefillConsumed, triggerToast]);

  const handleAddRule = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPartNumber.trim() || !newMappedOutput.trim()) {
      triggerToast("Missing required input fields on Sourcing Policy Form.", "warn");
      return;
    }

    setIsSubmitting(true);
    try {
      await apiClient.post("/api/taxonomy/rules", {
        sourceId: newPartNumber.trim(),
        ruleType: newRuleType,
        explanation: newLabel.trim() || (newRuleType.toUpperCase() + " Override Policy")
      });

      const newRule: SourcingRule = {
        id: "rule-" + Date.now(),
        ruleType: newRuleType,
        partNumber: newPartNumber.trim(),
        mappedOutput: newMappedOutput.trim(),
        label: newLabel.trim() || (newRuleType.toUpperCase() + " Override Policy"),
        vendor: newVendor,
        status: newStatus,
      };

      setSourcingRules((prev) => [newRule, ...prev]);
      setIsAddingRule(false);
      setNewPartNumber("");
      setNewMappedOutput("");
      setNewLabel("");
      triggerToast("Intelligence Policy Created & Continuous Feed Repopulated!", "success");
    } catch (error) {
      triggerToast("Failed to save Sourcing Rule to the server.", "warn");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleStartEdit = (rule: SourcingRule) => {
    setEditingRuleId(rule.id);
    setEditPartNumber(rule.partNumber);
    setEditMappedOutput(rule.mappedOutput);
    setEditLabel(rule.label);
    setEditVendor(rule.vendor);
    setEditStatus(rule.status);
  };

  const handleSaveEdit = (ruleId: string) => {
    if (!editPartNumber.trim() || !editMappedOutput.trim()) {
      triggerToast("Input parameters cannot be left blank during edit.", "warn");
      return;
    }

    setSourcingRules((prev) =>
      prev.map((r) =>
        r.id === ruleId
          ? {
              ...r,
              partNumber: editPartNumber.trim(),
              mappedOutput: editMappedOutput.trim(),
              label: editLabel.trim(),
              vendor: editVendor,
              status: editStatus,
            }
          : r
      )
    );
    setEditingRuleId(null);
    triggerToast("Sourcing Intelligence overridden and persistent layers flushed.", "success");
  };

  const handleDeleteRule = (ruleId: string) => {
    setSourcingRules((prev) => prev.filter((r) => r.id !== ruleId));
    triggerToast("Sourcing Intelligence policy permanently retired.", "success");
  };

  const handleSimulateAndPromote = (ruleId: string) => {
    setSimulatingRuleId(ruleId);
    setTimeout(() => {
      setSourcingRules((prev) => 
        prev.map((r) => r.id === ruleId ? { ...r, status: "active" } : r)
      );
      setSimulatingRuleId(null);
      triggerToast("Simulation safe! 0 conflicts found across 150 historical UCIDs. Rule promoted to ACTIVE.", "success");
    }, 2000);
  };

  return (
    <div 
      className="p-5 rounded-xl border flex flex-col gap-4 mt-2" 
      style={{
        backgroundColor: tokens.colors.background.card,
        borderColor: "rgba(74, 133, 253, 0.08)"
      }}
    >
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 pb-3 border-b border-white/5">
        <div className="flex items-center gap-2.5">
          <div className="w-8 h-8 rounded-lg bg-indigo-500/10 flex items-center justify-center border border-indigo-500/20">
            <BrainCircuit className="w-4.5 h-4.5 text-indigo-400" />
          </div>
          <div>
            <h3 className="text-sm font-semibold text-white flex items-center gap-2">
              Centralized Sourcing Intelligence & Override Registry
              <span className="text-[10px] bg-indigo-500/15 text-indigo-300 font-mono font-normal px-2 py-0.5 rounded border border-indigo-500/20">
                Learning Loop Database
              </span>
            </h3>
            <p className="text-[11px] text-gray-400 mt-0.5">
              Manage automated mapping policies, partner contractual cap targets, and hardware physical symmetry rules.
            </p>
          </div>
        </div>
        <div className="flex items-center gap-2 self-start sm:self-auto">
          <button
            onClick={() => {
              setIsAddingRule(false);
              setIsInjectingIntel(!isInjectingIntel);
            }}
            className="flex items-center gap-1.5 text-xs px-3.5 py-1.5 rounded-lg bg-indigo-500/10 border border-indigo-500/20 text-indigo-300 hover:bg-indigo-500/20 transition cursor-pointer select-none"
          >
            <Sparkles className="w-3.5 h-3.5" /> {isInjectingIntel ? "Close Learning Loop" : "Feed Intelligence"}
          </button>

          <button
            onClick={() => {
              setIsInjectingIntel(false);
              setIsAddingRule(!isAddingRule);
            }}
            className="flex items-center gap-1.5 text-xs px-3.5 py-1.5 rounded-lg bg-indigo-500 hover:bg-indigo-600 text-white font-bold transition cursor-pointer select-none border-0"
          >
            {isAddingRule ? (
              <>
                <X className="w-3.5 h-3.5" /> Close Panel
              </>
            ) : (
              <>
                <Plus className="w-3.5 h-3.5" /> Define Sourcing Override
              </>
            )}
          </button>
        </div>
      </div>

      <div className="p-3 rounded-lg bg-indigo-500/5 border border-indigo-500/10 text-[11px] text-indigo-200 flex gap-2.5 leading-normal">
        <Info className="w-4.5 h-4.5 text-indigo-400 shrink-0 mt-0.5" />
        <p>
          <strong>Core Engineering Mechanics:</strong> Sourcing Intel acts as an automated override shield. Every time you trigger 
          <strong className="text-white"> "Auto-Align Component" </strong> in the compliance anomalies above, the system corrects the active opportunity Bill of Materials 
          <em> and promotes the resolution mappings safely to this database in real-time</em>. You can also manually CRUD override directives below to preempt future configuration errors.
        </p>
      </div>

      <AnimatePresence>
        {isInjectingIntel && (
          <LearningLoopInjector 
            onClose={() => setIsInjectingIntel(false)} 
            onRuleDrafted={(rule) => {
              setSourcingRules(prev => [rule, ...prev]);
              setIsInjectingIntel(false);
              triggerToast("Semantic intelligence captured! Rule is now in Draft/Quarantine.", "success");
            }} 
          />
        )}
      </AnimatePresence>

      <AnimatePresence>
      {isAddingRule && (
        <motion.form 
          key="add-rule-form"
          initial={{ opacity: 0, height: 0 }}
          animate={{ opacity: 1, height: 'auto' }}
          exit={{ opacity: 0, height: 0 }}
          onSubmit={handleAddRule} 
          className="p-4 rounded-lg bg-black/45 border border-white/5 space-y-4 overflow-hidden"
        >
          <div className="text-[11px] font-bold uppercase text-gray-400 flex items-center gap-1 tracking-wider border-b border-white/5 pb-1">
            <Sparkles className="w-3.5 h-3.5 text-indigo-400 animate-pulse" /> Create New Sourcing Intelligence Directive
          </div>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-3 text-xs">
            <div>
              <label className="block text-gray-400 font-medium mb-1">Rule Class Category</label>
              <select
                value={newRuleType}
                onChange={(e) => setNewRuleType(e.target.value as SourcingRule["ruleType"])}
                className="w-full bg-surface-card border border-white/10 text-white p-2 rounded-lg font-mono focus:border-indigo-500/40 focus:outline-none"
              >
                <option value="substitution">Obsolete Substitution Mapping</option>
                <option value="price_cap">Price Contract Cap ($)</option>
                <option value="symmetry">Structural Geometry Symmetry</option>
                <option value="api_gateway">Credentials & API Gateway</option>
              </select>
            </div>

            <div>
              <label className="block text-gray-400 font-medium mb-1">Target SKU / Parameter Code</label>
              <input
                type="text"
                placeholder="e.g. 400-BPSB or Processor"
                value={newPartNumber}
                onChange={(e) => setNewPartNumber(e.target.value)}
                className="w-full bg-surface-card border border-white/10 text-white p-2 rounded-lg font-mono placeholder-gray-600 focus:border-indigo-500/40 focus:outline-none"
              />
            </div>

            <div>
              <label className="block text-gray-400 font-medium mb-1">Alignment Override Value</label>
              <input
                type="text"
                placeholder="e.g. P40424-B21 or 1190"
                value={newMappedOutput}
                onChange={(e) => setNewMappedOutput(e.target.value)}
                className="w-full bg-surface-card border border-white/10 text-white p-2 rounded-lg font-mono placeholder-gray-600 focus:border-indigo-500/40 focus:outline-none"
              />
            </div>

            <div>
              <label className="block text-gray-400 font-medium mb-1">Brand Sourcing Entity</label>
              <select
                value={newVendor}
                onChange={(e) => setNewVendor(e.target.value)}
                className="w-full bg-surface-card border border-white/10 text-white p-2 rounded-lg font-mono focus:border-indigo-500/40 focus:outline-none"
              >
                <option >HPE (Hewlett Packard Enterprise)</option>
                <option >Dell Technologies</option>
                <option value="Cisco">Cisco Systems</option>
                <option value="Juniper">Juniper Networks</option>
              </select>
            </div>
          </div>

          <div>
            <label className="block text-xs text-gray-400 font-medium mb-1">Directive Override Narrative / Explanation</label>
            <input
              type="text"
              placeholder="Brief justification logs e.g. Contract rate locked during 2026 Procurement summit"
              value={newLabel}
              onChange={(e) => setNewLabel(e.target.value)}
              className="w-full bg-surface-card border border-white/10 text-white p-2 rounded-lg text-xs placeholder-gray-600 focus:border-indigo-500/40 focus:outline-none"
            />
          </div>

          <div className="flex justify-end gap-2 text-xs pt-1">
            <button
              type="button"
              onClick={() => setIsAddingRule(false)}
              className="px-3.5 py-2 rounded-lg bg-white/5 text-gray-400 hover:bg-white/10 transition cursor-pointer font-bold border-0"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={isSubmitting}
              className="px-4 py-2 rounded-lg bg-indigo-500 text-white hover:bg-indigo-600 transition cursor-pointer font-bold flex items-center gap-1.5 border-0 disabled:opacity-50"
            >
              {isSubmitting ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Plus className="w-3.5 h-3.5" />}
              Save Sourcing Rule
            </button>
          </div>
        </motion.form>
      )}
      </AnimatePresence>

      <div className="overflow-x-auto rounded-lg border border-white/5 bg-black/15">
        <table className="w-full text-left border-collapse text-xs">
          <thead>
            <tr className="bg-black/40 border-b border-white/5 text-gray-400 font-semibold font-mono text-[10px] uppercase select-none tracking-wider">
              <th className="p-3">Target Reference Parameter</th>
              <th className="p-3">Category Class</th>
              <th className="p-3">Alignment Override</th>
              <th className="p-3">Sourcing Narrative / Rule Logs</th>
              <th className="p-3">Sourced Vendor</th>
              <th className="p-3">Origin</th>
              <th className="p-3">Operational State</th>
              <th className="p-3 text-center">Engine Control</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-white/5">
            {sourcingRules.map((rule) => {
              const isEditing = editingRuleId === rule.id;
              const isDraft = rule.status === "draft";
              return (
                <tr key={rule.id} className={`transition-colors ${isDraft ? 'bg-amber-500/5 border-l-2 border-l-amber-500' : 'hover:bg-white/2'}`}>
                  <td className="p-3 font-mono font-bold text-white whitespace-nowrap">
                    {isEditing ? (
                      <input
                        type="text"
                        value={editPartNumber}
                        onChange={(e) => setEditPartNumber(e.target.value)}
                        className="bg-black/50 border border-white/10 rounded px-2 py-1 font-mono text-white text-xs w-32 focus:outline-none focus:border-indigo-500/40"
                      />
                    ) : (
                      rule.partNumber
                    )}
                  </td>

                  <td className="p-3 font-medium whitespace-nowrap">
                    <span className={`px-2 py-0.5 rounded font-bold uppercase text-[9px] ${
                      rule.ruleType === "substitution"
                        ? "bg-purple-500/15 text-purple-300 border border-purple-500/20"
                        : rule.ruleType === "price_cap"
                        ? "bg-emerald-500/15 text-emerald-300 border border-emerald-500/20"
                        : rule.ruleType === "symmetry"
                        ? "bg-amber-500/15 text-amber-300 border border-amber-500/20"
                        : "bg-indigo-500/15 text-indigo-300 border border-indigo-500/20"
                    }`}>
                      {rule.ruleType}
                    </span>
                  </td>

                  <td className="p-3 font-mono text-white whitespace-nowrap">
                    {isEditing ? (
                      <input
                        type="text"
                        value={editMappedOutput}
                        onChange={(e) => setEditMappedOutput(e.target.value)}
                        className="bg-black/50 border border-white/10 rounded px-2 py-1 font-mono text-white text-xs w-32 focus:outline-none focus:border-indigo-500/40"
                      />
                    ) : (
                      <span className="font-bold text-indigo-300">
                        {rule.ruleType === "price_cap" && !isNaN(Number(rule.mappedOutput)) ? `$${Number(rule.mappedOutput).toLocaleString()}` : rule.mappedOutput}
                      </span>
                    )}
                  </td>

                  <td className="p-3 text-gray-400">
                    {isEditing ? (
                      <input
                        type="text"
                        value={editLabel}
                        onChange={(e) => setEditLabel(e.target.value)}
                        className="bg-black/50 border border-white/10 rounded px-2 py-1 text-white text-xs w-full focus:outline-none focus:border-indigo-500/40"
                      />
                    ) : (
                      rule.label
                    )}
                  </td>

                  <td className="p-3 font-bold text-gray-200">
                    {isEditing ? (
                      <select
                        value={editVendor}
                        onChange={(e) => setEditVendor(e.target.value)}
                        className="bg-black/50 border border-white/10 rounded px-2 py-1 text-white text-xs focus:outline-none"
                      >
                        <option >HPE</option>
                        <option >Dell</option>
                        <option value="Cisco">Cisco</option>
                        <option value="Juniper">Juniper</option>
                      </select>
                    ) : (
                      rule.vendor
                    )}
                  </td>

                  {/* Origin badge: auto-learned vs manual */}
                  <td className="p-3 whitespace-nowrap">
                    {rule.isAutoLearned ? (
                      <div className="flex flex-col gap-1">
                        <span className="inline-flex items-center gap-1 text-[9px] font-bold text-indigo-300 bg-indigo-500/10 border border-indigo-500/20 px-2 py-0.5 rounded font-mono uppercase">
                          🧠 Auto-Learned
                        </span>
                        {rule.learnedAt && (
                          <span className="text-[8px] text-gray-600 font-mono">
                            {new Date(rule.learnedAt).toLocaleString()}
                          </span>
                        )}
                      </div>
                    ) : (
                      <span className="inline-flex items-center gap-1 text-[9px] font-bold text-gray-400 bg-white/5 border border-white/10 px-2 py-0.5 rounded font-mono uppercase">
                        ✍️ Manual
                      </span>
                    )}
                  </td>

                  <td className="p-3 whitespace-nowrap">
                    {isEditing ? (
                      <select
                        value={editStatus}
                        onChange={(e) => setEditStatus(e.target.value as SourcingRule["status"])}
                        className="bg-black/50 border border-white/10 rounded px-2 py-1 text-white text-xs focus:outline-none"
                      >
                        <option value="active">Active</option>
                        <option value="draft">Draft</option>
                      </select>
                    ) : (
                      <span className={`inline-flex items-center gap-1.5 font-bold uppercase text-[9.5px] ${
                        rule.status === "active" ? "text-emerald-400" : "text-gray-500 animate-pulse"
                      }`}>
                        <span className={`w-1.5 h-1.5 rounded-full ${rule.status === "active" ? "bg-emerald-400" : "bg-gray-500"}`} />
                        {rule.status}
                      </span>
                    )}
                  </td>

                  <td className="p-3 text-center whitespace-nowrap">
                    {isEditing ? (
                      <div className="flex items-center justify-center gap-1.5">
                        <button
                          onClick={() => handleSaveEdit(rule.id)}
                          className="p-1 px-2 rounded bg-emerald-500/10 border border-emerald-500/30 text-emerald-400 hover:bg-emerald-500/20 transition cursor-pointer text-[10px] font-bold flex items-center gap-1"
                        >
                          <Save className="w-3.5 h-3.5" /> Save
                        </button>
                        <button
                          onClick={() => setEditingRuleId(null)}
                          className="p-1 px-2 rounded bg-white/5 border border-white/10 text-gray-400 hover:bg-white/10 transition cursor-pointer text-[10px] font-bold flex items-center gap-1"
                        >
                          <X className="w-3.5 h-3.5" /> Pin
                        </button>
                      </div>
                    ) : (
                      <div className="flex items-center justify-center gap-1.5">
                        {rule.status === "draft" && (
                          <button
                            onClick={() => handleSimulateAndPromote(rule.id)}
                            disabled={simulatingRuleId === rule.id}
                            className="p-1.5 px-2 rounded bg-amber-400/10 border border-amber-400/20 text-amber-400 hover:bg-amber-400/20 transition cursor-pointer text-[10px] font-bold flex items-center gap-1 disabled:opacity-50"
                            title="Simulate rule blast radius and promote to active"
                          >
                            {simulatingRuleId === rule.id ? (
                              <Loader2 className="w-3.5 h-3.5 animate-spin" />
                            ) : (
                              <Activity className="w-3.5 h-3.5" />
                            )}
                            Simulate & Promote
                          </button>
                        )}
                        <button
                          onClick={() => handleStartEdit(rule)}
                          className="p-1 px-2 rounded bg-indigo-500/10 border border-indigo-500/20 text-indigo-400 hover:bg-indigo-500/20 transition cursor-pointer text-[11px] font-medium flex items-center gap-0.5"
                          title="Edit override directive parameters"
                        >
                          <Edit3 className="w-3.5 h-3.5" /> Edit
                        </button>
                        <button
                          onClick={() => handleDeleteRule(rule.id)}
                          className="p-1.5 rounded bg-red-400/10 border border-red-400/20 text-red-400 hover:bg-red-400/20 transition cursor-pointer text-[11px] font-medium"
                          title="Delete policy permanently"
                        >
                          <Trash2 className="w-3.5 h-3.5" />
                        </button>
                      </div>
                    )}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

import React from "react";
import {
  FileSpreadsheet,
  Check,
  RefreshCw,
  ArrowRight,
  AlertTriangle,
  UploadCloud,
} from "lucide-react";

import { StatusBadge } from "../shared/StatusBadge";
import { Select } from "../shared/Select";
import { Button } from "../shared/Button";
import type { Solution, Config } from "../../types";

interface BoqResponsePayload {
  ucid: string;
  solutions?: Solution[];
  parsedSummary?: {
    vendorBrand: string;
    detectedChassis: string;
    initialConfidenceScore: number;
  };
}

interface BoqIngestWorkbookProps {
  selectedPreset: "hpe-legacy" | "dell-overcharge" | "cisco-asymmetry";
  setSelectedPreset: (
    val: "hpe-legacy" | "dell-overcharge" | "cisco-asymmetry",
  ) => void;
  boqFile: string;
  isBOQIngesting: boolean;
  boqProgress: number;
  boqResponse: BoqResponsePayload | null;
  boqError: string;
  onTriggerBOQParse: (
    fileName: string,
    preset: "hpe-legacy" | "dell-overcharge" | "cisco-asymmetry",
  ) => void;
  onSplitAndProvision: () => void;
}

export function BoqIngestWorkbook({
  selectedPreset,
  setSelectedPreset,
  boqFile,
  isBOQIngesting,
  boqProgress,
  boqResponse,
  boqError,
  onTriggerBOQParse,
  onSplitAndProvision,
}: BoqIngestWorkbookProps) {
  const boqPresets = [
    {
      key: "hpe-legacy",
      label: "HPE Enterprise Legacy Sheet (.xlsx)",
      file: "HPE_PARTNER_QUOTE_6130_EOL.xlsx",
    },
    {
      key: "dell-overcharge",
      label: "Dell Premier Portal Bid (.xlsx)",
      file: "DELL_PREMIER_R760_OVERCHARGE.xlsx",
    },
    {
      key: "cisco-asymmetry",
      label: "Cisco Symmetrical Layout (.xls)",
      file: "CISCO_UCS_M7S_ASYMMETRY.xls",
    },
  ];

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleBOQDrop = (e: React.DragEvent) => {
    e.preventDefault();
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      onTriggerBOQParse(e.dataTransfer.files[0].name, selectedPreset);
    }
  };

  const handleBOQPicked = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      onTriggerBOQParse(e.target.files[0].name, selectedPreset);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 text-left">
      {/* Main Upload / API workspace */}
      <div className="lg:col-span-2 space-y-4">
        <div className="bg-surface-elevated border border-white/5 rounded-xl p-6 space-y-6">
          <div className="flex flex-col sm:flex-row justify-between items-start gap-4">
            <div>
              <StatusBadge status="Step 1: Input Specifications" variant="info" />
              <h3 className="text-sm font-semibold text-white mt-1.5 animate-fadeIn">
                File Intake & Structural Splitting
              </h3>
              <p className="text-[11px] text-gray-500 mt-0.5 leading-relaxed">
                Upload the main spreadsheet containing hardware requirements. It
                will be mapped directly via active contract price catalogs.
              </p>
            </div>

            {/* Selector for Presets */}
            <div className="flex flex-col items-start sm:items-end gap-1 shrink-0 w-full sm:w-64">
              <span className="text-[10px] text-gray-400 font-mono">
                Simulate Document Profile:
              </span>
              <Select
                id="doc-profile-selector"
                value={selectedPreset}
                onChange={(e) => setSelectedPreset(e.target.value as "dell-overcharge" | "hpe-legacy" | "cisco-asymmetry")}
              >
                <option value="hpe-legacy" className="bg-surface-elevated text-white">HPE Legacy 6130 EOL</option>
                <option value="dell-overcharge" className="bg-surface-elevated text-white">Dell Premier Markup</option>
                <option value="cisco-asymmetry" className="bg-surface-elevated text-white">Cisco Asymmetry Layout</option>
              </Select>
            </div>
          </div>

          {/* Ingest Dropzone */}
          <div
            id="boq-dropzone"
            onDragOver={handleDragOver}
            onDrop={handleBOQDrop}
            onClick={() => document.getElementById("hub-boq-picker")?.click()}
            className={`border-2 border-dashed rounded-xl p-8 flex flex-col items-center justify-center text-center cursor-pointer transition-all duration-300 relative overflow-hidden bg-black/10 hover:bg-black/20 hover:border-sky-500/30 ${
              isBOQIngesting ? "border-sky-500/50" : "border-white/10"
            }`}
          >
            <input
              id="hub-boq-picker"
              type="file"
              onChange={handleBOQPicked}
              accept=".xlsx,.xls,.csv"
              className="hidden"
            />

            {isBOQIngesting ? (
              <div className="space-y-3 flex flex-col items-center animate-pulse">
                <RefreshCw className="w-8 h-8 text-sky-400 animate-spin" />
                <p className="text-xs font-bold text-white">
                  Directing to live spreadsheet compile endpoints...
                </p>
                <div className="w-48 h-1 bg-white/5 rounded-full overflow-hidden">
                  <div
                    className="h-full bg-sky-500 transition-all duration-200"
                    style={{ width: `${boqProgress}%` }}
                  />
                </div>
              </div>
            ) : boqResponse ? (
              <div className="space-y-3 flex flex-col items-center">
                <div className="w-10 h-10 rounded-full bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 flex items-center justify-center">
                  <Check className="w-5 h-5 animate-bounce" />
                </div>
                <div>
                  <p className="text-xs font-black text-emerald-300">
                    {boqFile || "Workbook-spec.xlsx"}
                  </p>
                  <p className="text-[10px] text-gray-400 mt-1 font-mono">
                    UCID session created:{" "}
                    <strong className="text-white">{boqResponse.ucid}</strong>
                  </p>
                </div>
              </div>
            ) : (
              <div className="space-y-2 flex flex-col items-center text-gray-400 hover:text-white">
                <div className="w-16 h-16 rounded-full bg-brand-indigo/10 flex items-center justify-center mb-2 border border-brand-indigo/20">
                  <UploadCloud className="w-8 h-8 text-brand-indigo" />
                </div>
                <div>
                  <p className="text-xl font-bold text-content-primary mb-1">
                    Awaiting Data Payload
                  </p>
                  <p className="text-content-muted text-sm max-w-sm mx-auto mb-4">
                    Upload a Vendor CSV or initiate a direct integration fetch.
                  </p>
                  <Button 
                    variant="outline"
                    onClick={(e) => {
                      e.stopPropagation();
                      document.getElementById("hub-boq-picker")?.click();
                    }}
                  >
                    Select File
                  </Button>
                </div>
              </div>
            )}
          </div>

          {/* Fast Demonstration Ingest Option */}
          {!boqResponse && !isBOQIngesting && (
            <div className="flex justify-center">
              <button
                id="run-ingest-btn"
                type="button"
                onClick={() => {
                  const matchedPreset = boqPresets.find(
                    (p) => p.key === selectedPreset,
                  );
                  onTriggerBOQParse(
                    matchedPreset?.file || "Workbook.xlsx",
                    selectedPreset,
                  );
                }}
                className="flex items-center gap-2 px-4 py-2 rounded-lg bg-sky-500/10 hover:bg-sky-500/15 border border-sky-500/20 text-sky-400 font-bold cursor-pointer transition focus:outline-none text-[10px]"
              >
                <FileSpreadsheet className="w-3.5 h-3.5" />
                <span>Run Backend API Ingest (Simulation Sandbox)</span>
              </button>
            </div>
          )}

          {/* API Response Display & Split Execution */}
          {boqResponse && (
            <div className="space-y-4 pt-4 border-t border-white/5 animate-fadeIn">
              <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
                <div className="p-3 rounded-lg bg-surface-card border border-white/5">
                  <p className="text-[9px] text-gray-500 font-mono lowercase">
                    vendor brand
                  </p>
                  <p className="text-xs font-bold text-white mt-1">
                    {boqResponse.parsedSummary?.vendorBrand}
                  </p>
                </div>
                <div className="p-3 rounded-lg bg-surface-card border border-white/5 col-span-2">
                  <p className="text-[9px] text-gray-500 font-mono lowercase">
                    detected key chassis sku
                  </p>
                  <p className="text-xs font-bold text-white mt-1 truncate">
                    {boqResponse.parsedSummary?.detectedChassis}
                  </p>
                </div>
                <div className="p-3 rounded-lg bg-surface-card border border-white/5">
                  <p className="text-[9px] text-gray-500 font-mono lowercase">
                    initial integrity confidence
                  </p>
                  <p className="text-xs font-mono font-bold text-emerald-400 mt-1">
                    {boqResponse.parsedSummary?.initialConfidenceScore}%
                  </p>
                </div>
              </div>

              <div className="bg-black/25 rounded-lg border border-white/5 p-4 space-y-2">
                <p className="text-[10px] text-gray-500 uppercase tracking-widest font-black">
                  extricated pipeline configs list
                </p>
                <div className="space-y-2 pt-1">
                  {(boqResponse?.solutions)?.map((sol: Solution, idx: number) => {
                    const firstVs = sol.vendorSubmissions?.[0];
                    const items =
                      firstVs?.configs?.flatMap((c: Config) => c.items) || [];
                    return (
                      <div
                        key={idx}
                        className="flex justify-between items-center bg-surface-card/60 p-3 rounded border border-white/5 hover:border-white/10"
                      >
                        <div className="flex items-center gap-2">
                          <span className="w-1.5 h-1.5 rounded-full bg-sky-400" />
                          <div>
                            <p className="text-xs font-bold text-white">
                              {firstVs?.label || sol.name}
                            </p>
                            <p className="text-[10px] text-gray-500 font-mono mt-0.5">
                              {items.length} hardware items mapped natively
                            </p>
                          </div>
                        </div>
                        <div className="text-right">
                          <p className="text-xs font-mono font-bold text-white">
                            ${firstVs?.totalPrice?.toLocaleString()}
                          </p>
                          <p className="text-[9px] text-emerald-400 font-medium">
                            calculated sav. $
                            {firstVs?.savings?.toLocaleString()}
                          </p>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>

              <div className="flex justify-end pt-2">
                <button
                  id="split-and-provision-btn"
                  type="button"
                  onClick={onSplitAndProvision}
                  className="px-5 py-2.5 rounded-lg bg-sky-500 hover:bg-sky-600 text-white font-bold cursor-pointer transition flex items-center gap-2 shadow-lg shadow-sky-500/10 focus:outline-none text-[11px]"
                >
                  <span>Split Configs into Active UCIDs</span>
                  <ArrowRight className="w-4 h-4" />
                </button>
              </div>
            </div>
          )}

          {boqError && (
            <div className="p-3 rounded bg-red-500/10 border border-red-500/20 text-red-400 text-xs flex items-center gap-2">
              <AlertTriangle className="w-4 h-4" />
              <span>{boqError}</span>
            </div>
          )}
        </div>
      </div>

      <div className="space-y-4">
        <div className="bg-surface-elevated border border-white/5 rounded-xl p-5 space-y-4">
          <h4 className="font-bold text-white uppercase tracking-wider text-[10px]">
            Config Intake Protocol
          </h4>
          <p className="text-gray-400 leading-relaxed text-[11px]">
            By routing raw BOQ docs centrally through the Ingestion Hub, our
            platform guarantees instant database alignment.
          </p>

          <div className="space-y-3 pt-2">
            <div className="flex items-start gap-2.5">
              <div className="w-5 h-5 rounded-full bg-emerald-500/10 text-emerald-400 flex items-center justify-center shrink-0">
                <Check className="w-3.5 h-3.5" />
              </div>
              <div>
                <span className="font-semibold text-white text-xs">
                  Strict Vendor Decoupling
                </span>
                <p className="text-gray-500 text-[10px] mt-0.5">
                  Configs are programmatically split by supplier types so they
                  never taint or interfere with each other during procurement
                  comparisons.
                </p>
              </div>
            </div>
            <div className="flex items-start gap-2.5">
              <div className="w-5 h-5 rounded-full bg-emerald-500/10 text-emerald-400 flex items-center justify-center shrink-0">
                <Check className="w-3.5 h-3.5" />
              </div>
              <div>
                <span className="font-semibold text-white text-xs">
                  Live Sourced Verification
                </span>
                <p className="text-gray-500 text-[10px] mt-0.5">
                  Immediately registers active sessions via real REST APIs,
                  saving developers from manually injecting complex data frames.
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from "react";
import { motion } from "motion/react";
import { useLocalStorageState } from "../../hooks/useLocalStorageState";
import { useWorkflowManager } from "../../hooks/useWorkflowManager";
import {
  Upload,
  FileSpreadsheet,
  Check,
  RefreshCw,
  ArrowRight,
  AlertTriangle,
  CheckCircle,
  Clock,
  Play,
  Activity,
  Loader2,
  AlertCircle,
  FileText,
  Download,
  Target,
  Cpu,
  HardDrive,
  Package,
  Plus,
  Search,
  Layers,
  Settings
} from "lucide-react";
import { useToast } from "../shared/ToastContext";
import type { UCID, Solution, BOMItem, AppView, ConstraintCheckResponse, ReconciliationResponse } from "../../types";

interface BoqResponsePayload {
  ucid: string;
  solutions?: Solution[];
  sourceFile?: string;
  parsedSummary?: {
    vendorBrand: string;
    detectedChassis: string;
    initialConfidenceScore: number;
  };
}
import { apiClient } from "../../services/apiClient";

import { BoqIngestWorkbook } from "./BoqIngestWorkbook";
import { TechnicalBomWorkspace } from "./TechnicalBomWorkspace";
import { HybridPortfolioOrchestration } from "./HybridPortfolioOrchestration";
import { LaunchStep } from "./LaunchStep";
import { ErrorBoundary } from "../shared/ErrorBoundary";
import { useIngestionLogic } from "./useIngestionLogic";

import { JobStreamer } from "../shared/JobStreamer";

interface IngestionHubProps {
  ucids: UCID[];
  setUcids: React.Dispatch<React.SetStateAction<UCID[]>>;
  onNavigate: (view: AppView) => void;
  onSelectMission: (id: string) => void;
  isPendingAPI?: boolean;
  setIsPendingAPI?: (pending: boolean) => void;
  pendingAPIMessage?: string;
  setPendingAPIMessage?: (msg: string) => void;
  setApiProgress?: (progress: number) => void;
}

export function IngestionHub({
  ucids,
  setUcids,
  onNavigate,
  onSelectMission,
  isPendingAPI = false,
  setIsPendingAPI = () => {},
  pendingAPIMessage = "",
  setPendingAPIMessage = () => {},
  setApiProgress = () => {},
}: IngestionHubProps) {
  // Workflow Manager Hook
  const {
    currentStepId,
    advanceStep,
    jumpToStep,
    auditLogs,
    currentStepIndex,
    resetWorkflow,
    selectedBomsForBatch,
    setSelectedBomsForBatch,
    isPortfolioActive,
    hpeSyncedConfigs,
    ciscoSyncedConfigs,
    manualBOMStatus,
    manualUploadedFiles,
    handleStartPortfolioPipeline,
    simulateManualUpload
  } = useIngestionLogic({
    ucids,
    setUcids,
    setIsPendingAPI,
    setPendingAPIMessage: setPendingAPIMessage as (msg: string) => void,
    setApiProgress: setApiProgress as (progress: number) => void
  });

  const { toast } = useToast();

  // Derived mode for backward compatibility with existing rendering logic
  const mode = currentStepId;
  const setMode = jumpToStep;

  const stepperSteps = useMemo(() => [
    { id: "boq", label: "1. BOQ Intake" },
    { id: "bom", label: "2. BOM Compile" },
    { id: "portfolio", label: "3. Hybrid Automation" },
    { id: "launch", label: "4. Launch", icon: Play },
  ], []);

  // ==========================================
  // SECTION A: BOQ SHEET INTAKE STATES & LOGIC
  // ==========================================
  const [selectedPreset, setSelectedPreset] = useLocalStorageState<
    "hpe-legacy" | "dell-overcharge" | "cisco-asymmetry"
  >("ingestion_boq_preset", "hpe-legacy");
  const [boqFile, setBoqFile] = useLocalStorageState<string>(
    "ingestion_boq_file",
    "",
  );
  const [isBOQIngesting, setIsBOQIngesting] = useState(false);
  const [boqProgress, setBoqProgress] = useState(0);
  const [boqResponse, setBoqResponse] = useLocalStorageState<BoqResponsePayload | null>(
    "ingestion_boq_response",
    null,
  );
  const [boqError, setBoqError] = useState<string>("");

  const [boqJobId, setBoqJobId] = useState<string | null>(null);

  const triggerBOQParse = async (
    fileName: string,
    preset: "hpe-legacy" | "dell-overcharge" | "cisco-asymmetry",
  ) => {
    setIsBOQIngesting(true);
    setBoqProgress(10);
    setBoqError("");
    setBoqFile(fileName);

    try {
      const response = await apiClient.post<{ job_id: string }>("/api/jobs", {
        type: "ingest",
        context: { ucid: "mock-ucid", config_id: "mock-cfg", solution_id: preset },
        parent_job_id: ""
      });
      setBoqJobId(response.data.job_id);
    } catch (err: unknown) {
      const errorObj = err as { message?: string };
      setBoqError(errorObj.message || "Failed to start BOQ ingest job.");
      setIsBOQIngesting(false);
    }
  };

  const onJobSuccess = async (result: unknown, context: unknown) => {
      // Instead of relying purely on Job result in the mock, we can fetch from our proper /api/boq/ingest to mimic exactly what happened previously
      const response = await apiClient.post<BoqResponsePayload>("/api/boq/ingest", {
        fileName: boqFile,
        presetType: (context as { solution_id: string }).solution_id,
        rawText: `[Manual central upload: ${boqFile}] presetType=${(context as { solution_id: string }).solution_id}`,
      });
      const data = response.data;
      setBoqResponse(data);
      setBoqProgress(100);
      setIsBOQIngesting(false);
      setBoqJobId(null);
  };

  const onJobError = (error: string, context: unknown) => {
      setBoqError(error);
      setIsBOQIngesting(false);
      setBoqJobId(null);
  };

  const handleSplitAndProvision = () => {
    if (!boqResponse) return;

    const prefix = "UCID-2026-";
    const generatedUcids: UCID[] = (boqResponse.solutions ?? []).map(
      (sol: Solution, idx: number) => {
        const displayId = `${prefix}${1700 + ucids.length + idx}`;
        const detailsText =
          sol.vendorSubmissions?.[0]?.configs?.[0]?.items
            ?.map(
              (i) => ` - ${i.name} (QTY ${i.quantity} @ $${i.unitPrice})`,
            )
            .join("\n") || "";

        return {
          id: `dynamic-hub-${displayId}`,
          displayId: displayId,
          name: `Sourced ${sol.vendorSubmissions?.[0]?.vendor || sol.name} Alignment Config`,
          solutionName: boqResponse.sourceFile,
          priority: idx === 0 ? "high" : "medium",
          projectRef: "PRJ-RECON-HUB",
          createdAt:
            new Date().toLocaleDateString() +
            " " +
            new Date().toLocaleTimeString([], {
              hour: "2-digit",
              minute: "2-digit",
            }),
          currentStep: "solution-design",
          completedSteps: ["boq-intake", "pre-intelligence"],
          rawBOM: `Workbook parsed via central Ingestion Hub.\n\nSource sheet: ${boqResponse.sourceFile}\nVendor Profile: ${sol.vendorSubmissions?.[0]?.vendor || sol.name}\n\nComponents Detail:\n${detailsText}`,
          solutions: [
            {
              id: `sol-${displayId}-primary`,
              name: sol.name,
              targetUcidId: `dynamic-hub-${displayId}`,
              vendorSubmissions: sol.vendorSubmissions?.map((vs) => ({ ...vs })) || [],
            },
          ],
          events: [
            {
              ts: new Date().toLocaleTimeString(),
              level: "info",
              msg: `Central BOQ split allocated to target container ${displayId}`,
            },
            {
              ts: new Date().toLocaleTimeString(),
              level: "ok",
              msg: `Primary spec loaded with initial compliance score and structural items.`,
            },
          ],
          snapshots: [],
        };
      },
    );

    setUcids((prev) => {
      const existingIds = prev.map((p) => p.displayId);
      const filteredGenerated = generatedUcids.filter(
        (g) => !existingIds.includes(g.displayId),
      );
      return [...filteredGenerated, ...prev];
    });

    toast(
      `BOQ intake completed! Allocated ${generatedUcids.length} UCID tracking slots successfully.`,
      "success",
      "Proceed to BOM Ingestion",
      () => {
        setMode("bom");
      }
    );

    setMode("bom");
    setSelectedUcidId(generatedUcids[0].id);
  };

  // ==========================================
  // SECTION B: TECHNICAL BOM WORKSPACE STATES
  // ==========================================
  const [selectedUcidId, setSelectedUcidId] = useLocalStorageState<string>(
    "ingestion_bom_ucid",
    ucids[0]?.id || "u1",
  );
  const [activeBOMFile, setActiveBOMFile] = useLocalStorageState<string>(
    "ingestion_bom_file",
    "",
  );
  const [isBOMIngesting, setIsBOMIngesting] = useState(false);
  const [bomProgress, setBomProgress] = useState(0);
  const [bomVerifyResult, setBomVerifyResult] = useLocalStorageState<ConstraintCheckResponse | null>(
    "ingestion_bom_verify",
    null,
  );
  const [bomReconResult, setBomReconResult] = useLocalStorageState<ReconciliationResponse | null>(
    "ingestion_bom_recon",
    null,
  );
  const [bomError, setBomError] = useState<string>("");

  const targetUcid = ucids.find((u) => u.id === selectedUcidId) || ucids[0];

  useEffect(() => {
    if (isBOQIngesting) {
      setApiProgress(boqProgress);
    } else if (isBOMIngesting) {
      setApiProgress(bomProgress);
    } else {
      setApiProgress(0);
    }
  }, [
    isBOQIngesting,
    isBOMIngesting,
    boqProgress,
    bomProgress,
    setApiProgress,
  ]);

  const triggerBOMParse = async (fileName: string) => {
    if (!targetUcid) {
      setBomError(
        "Please select or create an active UCID tracking container first!",
      );
      return;
    }

    setIsPendingAPI(true);
    setPendingAPIMessage(
      `Ingesting & validating technical BOM document: "${fileName}"...`,
    );
    setIsBOMIngesting(true);
    setBomProgress(20);
    setBomError("");
    setActiveBOMFile(fileName);
    setBomVerifyResult(null);
    setBomReconResult(null);

    try {
      const configItems =
        targetUcid.solutions[0]?.vendorSubmissions?.[0]?.configs?.flatMap(
          (c) => c.items,
        ) || [];
      const chassisSKU =
        configItems.find((i) => i.type === "Chassis")?.partNumber ||
        "P40411-B21";
      const cpuSKU =
        configItems.find((i) => i.type === "Processor")?.partNumber ||
        "815100-B21";
      const ramQuantity =
        configItems.find((i) => i.type === "Memory")?.quantity || 5;

      const constraintsRes = await apiClient.post("/api/taxonomy/check-constraints", {
        chassisSKU,
        cpuSKU,
        ramQuantity,
        psuWattsCount: 750,
      });

      if (!constraintsRes.success) throw constraintsRes;
      const constraintsData = constraintsRes.data as ConstraintCheckResponse;
      setBomVerifyResult(constraintsData);

      const reconRes = await apiClient.post("/api/reconciliation/compare", {
        solutions: targetUcid.solutions,
      });

      if (!reconRes.success) throw reconRes;
      const reconData = reconRes.data as ReconciliationResponse;

      setBomProgress(100);
      setBomReconResult(reconData);

      setUcids((prev) =>
        prev.map((u) => {
          if (u.id === selectedUcidId) {
            const updatedSolutions = u.solutions.map((sol) => {
              const matchedMatrix = reconData.matrix?.find?.(
                (m: Record<string, unknown>) => m.solutionId === sol.id,
              );
              return {
                ...sol,
                vendorSubmissions:
                  sol.vendorSubmissions?.map((vs) => ({
                    ...vs,
                    complianceScore: matchedMatrix
                      ? matchedMatrix.deliveryConfidenceRating
                      : vs.complianceScore,
                  })) || [],
              };
            });

            const newEvent = {
              ts: new Date().toLocaleTimeString(),
              level: constraintsData.isCompliant
                ? ("ok" as const)
                : ("warn" as const),
              msg: `BOM Sheet "${fileName}" verified centrally. Compliance Rating matched: ${updatedSolutions[0]?.vendorSubmissions?.[0]?.complianceScore ?? "98"}%`,
            };

            return {
              ...u,
              currentStep: "post-intelligence",
              completedSteps: Array.from(
                new Set([
                  ...u.completedSteps,
                  "solution-design",
                  "vendor-provisioning",
                  "post-intelligence",
                ]),
              ),
              solutions: updatedSolutions,
              events: [newEvent, ...u.events],
            };
          }
          return u;
        }),
      );

      toast(
        "Automated intelligence mapping initialized.",
        "success",
        "View Results",
        () => setMode("portfolio")
      );
      advanceStep();
      setIsBOMIngesting(false);
      setIsPendingAPI(false);
    } catch (err: unknown) {
      const errorObj = err as { message?: string; error?: { message?: string } };
      toast(errorObj.error?.message || errorObj.message || "Backend Verification Failed.", "error");
      setIsBOMIngesting(false);
      setIsPendingAPI(false);
    }
  };

  const triggerBatchReconciliation = async () => {
    if (selectedBomsForBatch.length === 0) {
      toast(
        "Please select at least one uploaded BOM configuration to reconcile.",
        "warn"
      );
      return;
    }

    try {
      setIsPendingAPI(true);
      setPendingAPIMessage(
        "Initiating Enterprise Multi-UCID Comparison Sweep...",
      );

      await apiClient.post("/api/reconciliation/compare", {
        solutions: selectedBomsForBatch
      });

      setUcids((prev) => {
        return prev.map((u) => {
          if (!selectedBomsForBatch.includes(u.id)) {
            return u;
          }

          const updatedSolutions = u.solutions.map((sol) => {
            const repairedSubmissions =
              sol.vendorSubmissions?.map((vs) => {
                const repairedConfigs =
                  vs.configs?.map((c) => {
                    const repairedItems =
                      c.items?.map((it) => {
                        if (it.partNumber === "815100-B21") {
                          return {
                            ...it,
                            partNumber: "P40424-B21",
                            name: "Intel Xeon Gold 6430 32-Core 2.1GHz Processor (Gen11) [RECONCILED]",
                            unitPrice: 2150,
                          };
                        }
                        if (
                          it.partNumber === "400-BPSB" &&
                          it.unitPrice > 1190
                        ) {
                          return {
                            ...it,
                            unitPrice: 1190,
                            name: "Dell 3.84TB SAS Read Intensive SSD [RECONCILED]",
                          };
                        }
                        if (
                          vs.vendor === "Cisco" &&
                          it.type === "Memory" &&
                          it.quantity % 8 !== 0
                        ) {
                          return {
                            ...it,
                            quantity: 8,
                            name: "UCS 64GB DDR5 memory module RDIMM [RECONCILED]",
                          };
                        }
                        return it;
                      }) || [];
                    const newConfigSum = repairedItems.reduce(
                      (acc, curr) => acc + curr.unitPrice * curr.quantity,
                      0,
                    );
                    return {
                      ...c,
                      items: repairedItems,
                      totalPrice: newConfigSum,
                      savings: Math.max(0, c.originalPrice - newConfigSum),
                    };
                  }) || [];
                const newVsSum = repairedConfigs.reduce(
                  (acc, c) => acc + c.totalPrice,
                  0,
                );
                return {
                  ...vs,
                  configs: repairedConfigs,
                  totalPrice: newVsSum,
                  savings: Math.max(0, vs.originalPrice - newVsSum),
                  complianceScore: 100,
                };
              }) || [];

            return {
              ...sol,
              vendorSubmissions: repairedSubmissions,
            };
          });

          return {
            ...u,
            syncStatus: "Synced" as const,
            currentStep: "comparison" as const,
            completedSteps: Array.from(
              new Set([
                ...u.completedSteps,
                "boq-intake",
                "pre-intelligence",
                "solution-design",
                "vendor-provisioning",
                "post-intelligence",
                "comparison",
              ]),
            ),
            solutions: updatedSolutions,
            events: [
              {
                ts: new Date().toLocaleTimeString(),
                level: "ok" as const,
                msg: "✓ Global Batch Reconciliation Sweep executed successfully. Hardware constraints satisfied, discrepancies zeroed, and records synchronized.",
              },
              ...u.events,
            ],
          };
        });
      });

      toast(
        `Multi-UCID Batch Reconciliation sweep completed! ${selectedBomsForBatch.length} configurations synchronized.`,
        "success",
        "Proceed to Hybrid Automation",
        () => advanceStep()
      );
    } finally {
      setIsPendingAPI(false);
    }
  };  return (
    <ErrorBoundary>
      <motion.div 
        className="flex flex-col gap-6 relative select-none"
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4, ease: "easeOut", staggerChildren: 0.1 }}
      >
        {/* Visual Title Header */}
        <div className="flex flex-col gap-4 bg-surface-header border border-indigo-500/10 p-5 rounded-xl">
          {/* Unified Pipeline Active Banner */}
          <div className="p-3 bg-indigo-500/5 border border-indigo-500/20 rounded-xl flex items-center justify-between text-left gap-4">
            <div>
              <span className="text-[9px] font-bold text-indigo-400 font-mono tracking-wider uppercase bg-indigo-500/10 px-2 py-0.5 rounded">
                ● Unified State Sync Connected
              </span>
              <p className="text-[11px] text-white font-semibold mt-1">
                Centralized Sourcing Ingestion & Worksheets
              </p>
              <p className="text-[10px] text-gray-400 mt-0.5 leading-snug">
                This hub is the single source of truth for all external spreadsheets. Uploads parsed here automatically propagate to parallel <span className="text-gray-300 font-medium">Live Mission Tracks</span> and <span className="text-gray-300 font-medium">BOM Reconciliation Diff</span> dashboards.
              </p>
            </div>
            <div className="text-right shrink-0">
              <span className="text-[10px] font-mono text-emerald-400 font-bold block">
                Status: Synchronized
              </span>
              <span className="text-[9px] text-gray-500 font-sans block mt-0.5 animate-fadeIn">
                Active opportunities: {ucids.length}
              </span>
            </div>
          </div>

          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div className="flex items-center gap-3 w-full">
              <div className="w-10 h-10 rounded-xl bg-sky-500/10 border border-sky-500/20 flex items-center justify-center shrink-0">
                <Upload className="w-5 h-5 text-sky-400" />
              </div>
              <div className="flex-1 text-left">
                <h1 className="text-sm font-semibold text-white">
                  Centralized BOQ & BOM Ingestion Hub
                </h1>
                <p className="text-[10px] text-gray-400 mt-0.5 leading-relaxed">
                  Upload raw Bills of Quantities or Technical Bills of Materials and get real-time contract audits.
                </p>
              </div>
              {auditLogs.length > 0 && currentStepIndex > 0 && (
                <div className="hidden lg:flex items-center gap-2 bg-indigo-500/10 border border-indigo-500/20 px-3 py-1.5 rounded-lg shrink-0 text-left">
                  <Clock className="w-3.5 h-3.5 text-indigo-400" />
                  <div className="text-right">
                    <p className="text-[9px] text-gray-400 font-mono uppercase">
                      Last Active Checkpoint
                    </p>
                    <p className="text-[10px] font-bold text-white capitalize">
                      {currentStepId}
                    </p>
                  </div>
                  <button
                    type="button"
                    onClick={() => resetWorkflow()}
                    className="ml-2 px-2 py-1 bg-red-500/10 hover:bg-red-500/20 text-red-400 rounded text-[9px] font-bold transition uppercase cursor-pointer"
                  >
                    Restart
                  </button>
                </div>
              )}
            </div>

            {/* Lifecycle Workflow Stepper */}
            <div className="flex mt-5 bg-surface-elevated rounded-lg border border-white/5 shrink-0 overflow-hidden relative">
              <div className="absolute inset-0 bg-indigo-500/5" />
              <div className="relative flex w-full">
                {stepperSteps.map((step, idx) => {
                  const isActive = currentStepId === step.id;
                  const isPast =
                    ["boq", "bom", "portfolio", "launch"].indexOf(currentStepId) >
                    idx;

                  return (
                    <button
                      key={step.id}
                      type="button"
                      onClick={() => jumpToStep(step.id)}
                      className={`flex-1 min-w-[120px] justify-center flex items-center px-4 py-2 border-r border-white/5 last:border-r-0 font-bold tracking-tight text-[10px] uppercase transition cursor-pointer gap-1.5 relative ${
                        isActive
                          ? "bg-sky-500 text-white shadow-lg shadow-sky-500/20 font-black"
                          : isPast
                            ? "bg-emerald-500/10 text-emerald-400 hover:text-emerald-300"
                            : "text-gray-400 hover:bg-white/5 hover:text-white"
                      }`}
                    >
                      {isPast && !isActive && (
                        <Check className="w-3.5 h-3.5 shrink-0" />
                      )}
                      {step.icon && (
                        <step.icon
                          className={`w-3.5 h-3.5 ${isActive ? "text-white" : ""} shrink-0`}
                        />
                      )}
                      <span className="truncate">{step.label}</span>
                      {isActive && (
                        <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-white/20" />
                      )}
                    </button>
                  );
                })}
              </div>
            </div>
          </div>
        </div>

      {mode === "boq" && (
        <>
          <BoqIngestWorkbook
            selectedPreset={selectedPreset}
            setSelectedPreset={setSelectedPreset}
            boqFile={boqFile}
            isBOQIngesting={isBOQIngesting}
            boqProgress={boqProgress}
            boqResponse={boqResponse}
            boqError={boqError}
            onTriggerBOQParse={triggerBOQParse}
            onSplitAndProvision={handleSplitAndProvision}
          />
          {boqJobId && (
            <JobStreamer
              jobId={boqJobId}
              context={{ ucid: "mock-ucid", config_id: "mock-cfg", solution_id: selectedPreset }}
              onSuccess={onJobSuccess}
              onError={onJobError}
            />
          )}
        </>
      )}

      {mode === "bom" && (
        <TechnicalBomWorkspace
          ucids={ucids}
          selectedUcidId={selectedUcidId}
          setSelectedUcidId={setSelectedUcidId}
          bomVerifyResult={bomVerifyResult}
          setBomVerifyResult={setBomVerifyResult}
          bomReconResult={bomReconResult}
          setBomReconResult={setBomReconResult}
          activeBOMFile={activeBOMFile}
          setActiveBOMFile={setActiveBOMFile}
          isBOMIngesting={isBOMIngesting}
          setIsBOMIngesting={setIsBOMIngesting}
          bomProgress={bomProgress}
          setBomProgress={setBomProgress}
          selectedBomsForBatch={selectedBomsForBatch}
          setSelectedBomsForBatch={setSelectedBomsForBatch}
          bomError={bomError}
          onTriggerBOMParse={triggerBOMParse}
          onTriggerBatchReconciliation={triggerBatchReconciliation}
          onSelectMission={onSelectMission}
        />
      )}

      {mode === "portfolio" && (
        <HybridPortfolioOrchestration
          isPortfolioActive={isPortfolioActive}
          hpeSyncedConfigs={hpeSyncedConfigs}
          ciscoSyncedConfigs={ciscoSyncedConfigs}
          manualBOMStatus={manualBOMStatus}
          manualUploadedFiles={manualUploadedFiles}
          onStartPortfolioPipeline={handleStartPortfolioPipeline}
          onSimulateManualUpload={simulateManualUpload}
          onAdvanceStep={advanceStep}
          activeUCID={targetUcid}
        />
      )}

      {mode === "launch" && <LaunchStep onNavigate={onNavigate} />}
      </motion.div>
    </ErrorBoundary>
  );
}

import React from "react";
import {
  RefreshCw,
  Upload,
  Settings,
  CheckCircle,
  AlertTriangle,
  Layers,
  Info,
  Zap,
  ShieldCheck,
  DollarSign,
  Clock,
  ChevronRight,
  FileSpreadsheet,
  ShieldCheck as FileCheck,
} from "lucide-react";
import { StatusBadge } from "../shared/StatusBadge";
import { Select } from "../shared/Select";
import type { UCID, ConstraintCheckResponse, ReconciliationResponse } from "../../types";

interface TechnicalBomWorkspaceProps {
  ucids: UCID[];
  selectedUcidId: string;
  setSelectedUcidId: (id: string) => void;
  bomVerifyResult: ConstraintCheckResponse | null;
  setBomVerifyResult: (res: ConstraintCheckResponse | null) => void;
  bomReconResult: ReconciliationResponse | null;
  setBomReconResult: (res: ReconciliationResponse | null) => void;
  activeBOMFile: string;
  setActiveBOMFile: (file: string) => void;
  isBOMIngesting: boolean;
  setIsBOMIngesting: (ingesting: boolean) => void;
  bomProgress: number;
  setBomProgress: (progress: number) => void;
  selectedBomsForBatch: string[];
  setSelectedBomsForBatch: React.Dispatch<React.SetStateAction<string[]>>;
  bomError: string;
  onTriggerBOMParse: (fileName: string) => void;
  onTriggerBatchReconciliation: () => void;
  onSelectMission: (id: string) => void;
}

export function TechnicalBomWorkspace({
  ucids,
  selectedUcidId,
  setSelectedUcidId,
  bomVerifyResult,
  setBomVerifyResult,
  bomReconResult,
  setBomReconResult,
  activeBOMFile,
  setActiveBOMFile,
  isBOMIngesting,
  setIsBOMIngesting,
  bomProgress,
  setBomProgress,
  selectedBomsForBatch,
  setSelectedBomsForBatch,
  bomError,
  onTriggerBOMParse,
  onTriggerBatchReconciliation,
  onSelectMission,
}: TechnicalBomWorkspaceProps) {
  const targetUcid = ucids.find((u) => u.id === selectedUcidId) || ucids[0];

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleBOMDrop = (e: React.DragEvent) => {
    e.preventDefault();
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      onTriggerBOMParse(e.dataTransfer.files[0].name);
    }
  };

  const handleBOMPicked = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      onTriggerBOMParse(e.target.files[0].name);
    }
  };

  return (
    <div className="flex flex-col gap-6 w-full text-left">
      {/* Universal Multi-UCID Batch Reconciliation Control Board */}
      <div className="p-6 bg-gradient-to-r from-indigo-950/40 via-surface-elevated to-indigo-950/20 border border-sky-400/10 rounded-xl flex flex-col gap-6 shadow-2xl text-left"> 
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
          <div className="space-y-2 max-w-2xl text-left">
            <span className="text-[9.5px] bg-indigo-500/15 text-indigo-400 border border-indigo-500/20 px-2.5 py-1 rounded font-black uppercase tracking-wider">
              Sweep Coordinator Engine
            </span>
            <h2 className="text-sm font-semibold text-white tracking-tight">
              Global Multi-UCID Batch Reconciliation Control Board
            </h2>
            <p className="text-[11px] text-gray-400 leading-relaxed">
              Initiate a complete multi-UCID data sweep once your vendor sheets
              (HPE, Dell & Cisco BOM lists) are active. This reconciles EOL
              processor warnings, recalculates contractual unit pricing
              variances, and updates consistency status badges across all other
              system tabs.
            </p>
          </div>

          <button
            id="comparison-sweep-btn"
            type="button"
            onClick={onTriggerBatchReconciliation}
            className="w-full md:w-auto px-5 py-3 rounded-lg bg-sky-500 hover:bg-sky-600 border border-sky-400/25 text-white font-extrabold cursor-pointer transition flex items-center justify-center gap-2 shadow-2xl text-[10.5px] tracking-wider uppercase shrink hover:scale-[1.02] active:scale-[0.98]"
          >
            <RefreshCw className="w-4 h-4 text-white animate-spin-slow shrink-0" />
            <span className="truncate">
              Initiate Multi-UCID Comparison Sweep
            </span>
          </button>
        </div>

        {/* Selection Grid inside Control Board */}
        <div className="space-y-3 w-full bg-black/20 p-4 rounded-xl border border-white/5">
          <div className="flex justify-between items-center pb-2 border-b border-white/5">
            <span className="text-[10px] text-indigo-400 uppercase font-bold tracking-wider">
              Select active supplier BOMs / UCID configurations to sweep:
            </span>
            <div className="flex gap-2">
              <button
                type="button"
                onClick={() => setSelectedBomsForBatch(ucids.map((u) => u.id))}
                className="text-[9.2px] text-sky-400 hover:underline cursor-pointer font-bold uppercase tracking-wider"
              >
                Select All
              </button>
              <span className="text-gray-700 text-[9px]">|</span>
              <button
                type="button"
                onClick={() => setSelectedBomsForBatch([])}
                className="text-[9.2px] text-sky-400 hover:underline cursor-pointer font-bold uppercase tracking-wider"
              >
                Clear All
              </button>
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-3">
            {ucids.map((u) => {
              const isChecked = selectedBomsForBatch.includes(u.id);
              return (
                <label
                  key={u.id}
                  className={`flex items-start gap-3 p-2.5 rounded-lg border transition cursor-pointer select-none ${
                    isChecked
