                        "Equipment Item Sourced Name": item.name,
                        "Equipment Category Type": item.type,
                        "Allocated Quantity": item.quantity,
                        "Supplier Unit Price ($)": item.unitPrice,
                        "Extended Subtotal ($)": item.quantity * item.unitPrice,
