                      </div>
                    </td>
                  </motion.tr>

                  {/* Group Body list */}
                  <AnimatePresence>
                  {!isCollapsed &&
                    filteredRows.map((row) => (
                      <MemoizedRow key={row.id} row={row as TableRowType & { hasAlert: boolean; alertId: string; alertTitle: string }} handleAutoHeal={handleAutoHeal} />
