import React, { useState, useEffect, useMemo } from "react";
import { motion, AnimatePresence } from "motion/react";
import { Database, Globe, Target, Search, ArrowUpRight, Loader2, Sparkles } from "lucide-react";
import type { AppView, UCID, Vendor, CatalogSKU } from "../../types";
import { ErrorBoundary } from "../shared/ErrorBoundary";

interface SearchViewProps {
  query: string;
  ucids: UCID[];
  vendors: Vendor[];
  catalogSkus: CatalogSKU[];
  onNavigate: (view: AppView) => void;
  onSelectMission: (id: string) => void;
  onSearchChange?: (newQuery: string) => void;
}

function highlightText(text: string, query: string) {
  if (!query || !text) return <>{text}</>;
  const normQuery = query.trim();
  if (!normQuery) return <>{text}</>;

  try {
    const escapedQuery = normQuery.replace(/[-\/\\^$*+?.()|[\]{}]/g, "\\$&");
    const regex = new RegExp(`(${escapedQuery})`, "gi");
    const parts = text.split(regex);
    return (
      <>
        {parts.map((part, index) =>
          regex.test(part) ? (
            <mark
              key={index}
              className="bg-amber-500/25 text-amber-300 px-0.5 rounded-sm font-semibold"
            >
              {part}
            </mark>
          ) : (
            part
          ),
        )}
      </>
    );
  } catch (e) {
    return <>{text}</>;
  }
}

export function SearchView({
  query,
  ucids,
  vendors,
  catalogSkus,
  onNavigate,
  onSelectMission,
  onSearchChange,
}: SearchViewProps) {
  const [localInput, setLocalInput] = useState(query);

  useEffect(() => {
    setLocalInput(query);
  }, [query]);

  const activeQuery = localInput;
  const normQuery = activeQuery.toLowerCase().trim();

  const handleSearchSubmit = (val: string) => {
    setLocalInput(val);
    if (onSearchChange) {
      onSearchChange(val);
    }
  };

  // Filter matched records with useMemo
