import React, { useState, useEffect, useMemo } from 'react';
import { motion } from "motion/react";
import { Hammer, Check, Loader2 } from 'lucide-react';
import type { UCID, Solution, VendorSubmission, AppView } from '../../types';
import type { ConfigItem, UcidContainer } from '../../types/data';
import { StepIntake } from './StepIntake';
import { StepWorkspace } from './StepWorkspace';
import { ErrorBoundary } from '../shared/ErrorBoundary';
import { apiClient } from '../../services/apiClient';

interface SolutionBuilderProps {
  ucids: UCID[];
  setUcids: React.Dispatch<React.SetStateAction<UCID[]>>;
  onNavigate: (view: AppView) => void;
  setDeployedSolution: React.Dispatch<React.SetStateAction<{ name: string; ucidCount: number; timestamp: number } | null>>;
  onSelectMission: (id: string) => void;
}

export const SolutionBuilder = React.memo(function SolutionBuilder({
  ucids,
  setUcids,
  onNavigate,
  setDeployedSolution,
  onSelectMission
}: SolutionBuilderProps) {
  // Step 1: Intake | Step 2: Builder
  const [step, setStep] = useState<1 | 2>(1);
  const [solutionName, setSolutionName] = useState('Project Horizon — UCID Solution v1');
  const [isMultiUcid, setIsMultiUcid] = useState(false);

  // Sourcing containers state
  const [ucidsList, setUcidsList] = useState<UcidContainer[]>([]);

  // Sourcing configurations from Sheet Parser
  const [configs, setConfigs] = useState<ConfigItem[]>([]);

  const [selectedConfigId, setSelectedConfigId] = useState<string>('cfg-1');
  const [isIngested, setIsIngested] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    async function fetchInitialData() {
      try {
        const res = await apiClient.get<{ ucidsList: UcidContainer[], configs: ConfigItem[] }>("/api/solution-builder/init");
        if (res.success && res.data) {
          setUcidsList(res.data.ucidsList);
          setConfigs(res.data.configs);
        }
      } catch (err) {
        console.error("Failed to load initial solution builder mock data", err);
      } finally {
        setIsLoading(false);
      }
    }
    fetchInitialData();
  }, []);

  // Memoized calculations on configurations list for performance optimization
  const { totalConfigPrice, totalOriginalConfigPrice, uniqueVendorsCount } = useMemo(() => {
    let totalPriceSum = 0;
    let originalPriceSum = 0;
    const vendorsSet = new Set<string>();
    configs.forEach(c => {
      totalPriceSum += c.totalPrice;
      originalPriceSum += c.originalPrice;
      vendorsSet.add(c.vendor);
    });
    return {
      totalConfigPrice: totalPriceSum,
      totalOriginalConfigPrice: originalPriceSum,
      uniqueVendorsCount: vendorsSet.size
    };
  }, [configs]);

  // Switch configs across UCID boxes
  const assignConfigToUcid = (configId: string, ucidId: string) => {
    setConfigs(prev =>
      prev.map(c => (c.id === configId ? { ...c, targetUcidId: ucidId } : c))
    );
  };

  // Add a new UCID container
  const handleAddUcid = () => {
    const prefix = 'UCID-2026-';
    const nextNum = 1700 + ucidsList.length;
    const newId = `${prefix}${nextNum}`;
    const newContainer: UcidContainer = {
      id: newId,
      name: `Sub-deployment ${ucidsList.length + 1}`,
      reasoning: 'Assigned configurations to secondary isolated cloud environments.',
      locked: false,
      syncStatus: 'Pending'
    };

    setUcidsList([...ucidsList, newContainer]);

    if (ucidsList.length === 1) {
      assignConfigToUcid('cfg-2', newId);
    }
  };

  // Toggle Single vs Multi UCID containers
  const toggleMultiUcidMode = (enabled: boolean) => {
    setIsMultiUcid(enabled);
    if (!enabled) {
      const firstId = ucidsList[0]?.id || 'UCID-2026-1699';
      setConfigs(prev => prev.map(c => ({ ...c, targetUcidId: firstId })));
    } else {
      if (ucidsList.length < 2) {
        handleAddUcid();
      }
    }
  };

  const updateContainerName = (id: string, name: string) => {
    setUcidsList(prev => prev.map(u => (u.id === id ? { ...u, name } : u)));
  };

  const updateContainerReasoning = (id: string, reasoning: string) => {
    setUcidsList(prev => prev.map(u => (u.id === id ? { ...u, reasoning } : u)));
  };

  const toggleContainerLock = (id: string) => {
    setUcidsList(prev => prev.map(u => (u.id === id ? { ...u, locked: !u.locked } : u)));
  };

  // Deploy to Live Parallel Mission Control
  const handleDeployToMissionControl = () => {
    const activeUcids = isMultiUcid ? ucidsList : [ucidsList[0]];

    const generatedUcids: UCID[] = activeUcids.map((container, containerIdx) => {
      const assignedConfigs = configs.filter(c => c.targetUcidId === container.id || !isMultiUcid);

      const vendorGroups: Record<string, typeof assignedConfigs> = {};
      assignedConfigs.forEach(cfg => {
        if (!vendorGroups[cfg.vendor]) {
          vendorGroups[cfg.vendor] = [];
        }
        vendorGroups[cfg.vendor].push(cfg);
      });

      const vendorSubmissions: VendorSubmission[] = Object.keys(vendorGroups).map(vendorKey => {
        const vendorCfgs = vendorGroups[vendorKey];
        const vTotalPrice = vendorCfgs.reduce((sum, c) => sum + c.totalPrice, 0);
        const vOrgPrice = vendorCfgs.reduce((sum, c) => sum + c.originalPrice, 0);
        return {
          id: `vs-${container.id}-${vendorKey}`,
          vendor: vendorKey,
          label: `${vendorKey} Integrated Sourcing`,
          totalPrice: vTotalPrice,
          originalPrice: vOrgPrice,
          savings: vOrgPrice - vTotalPrice,
          complianceScore: 98,
          configs: vendorCfgs.map(cfg => ({
            id: cfg.id,
            name: cfg.name,
            totalPrice: cfg.totalPrice,
            originalPrice: cfg.originalPrice,
            savings: cfg.originalPrice - cfg.totalPrice,
            items: cfg.items.map(item => ({ ...item }))
          }))
        };
      });

      const masterSolution: Solution = {
        id: `sol-master-${container.id}`,
        name: 'Master Architectural Solution',
        targetUcidId: container.id,
        vendorSubmissions: vendorSubmissions
      };

      return {
        id: `dynamic-${container.id}`,
        displayId: container.id,
        name: `${solutionName} — ${container.name}`,
        solutionName: solutionName,
        priority: containerIdx === 0 ? 'high' : 'medium',
        projectRef: 'PRJ-HORIZON-2026',
        createdAt: new Date().toLocaleDateString() + ' ' + new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        currentStep: 'solution-design', // Incepted straight at the architecture phase
        completedSteps: ['boq-intake', 'pre-intelligence'],
        rawBOM: `Assigned Equipment configurations:\n` + assignedConfigs.map(c => ` - ${c.name} (${c.vendor} equipment)`).join('\n') + `\n\nReasoning: ${container.reasoning}`,
        solutions: [masterSolution],
        events: [
          { ts: '13:59:32', level: 'info', msg: `Ingested Raw Sheet configurations into Sourcing platform` },
          { ts: '13:59:45', level: 'ok', msg: `Auto-assigned container: ${container.name} (${container.id})` },
          { ts: '13:59:52', level: 'ok', msg: `Catalog validation finished with optimal load metrics` }
        ],
        snapshots: []
      };
    });

    setUcids(prev => {
      const idsToExclude = generatedUcids.map(g => g.id);
      const filteredPrev = prev.filter(p => !idsToExclude.includes(p.id));
      return [...generatedUcids, ...filteredPrev];
    });

    setDeployedSolution({
      name: solutionName,
      ucidCount: generatedUcids.length,
      timestamp: Date.now()
    });

    onSelectMission(generatedUcids[0].id);
  };

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 gap-3">
        <Loader2 className="w-8 h-8 text-indigo-400 animate-spin" />
        <p className="text-xs text-gray-500 font-mono">Loading builder mock data...</p>
      </div>
    );
  }

  return (
    <ErrorBoundary>
      <motion.div 
        className="flex flex-col gap-4 text-xs select-none"
        initial={{ y: 10, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.4, ease: "easeOut", staggerChildren: 0.1 }}
      >
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-surface-elevated border border-indigo-500/10 p-5 rounded-xl">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-indigo-500/15 border border-indigo-500/25 flex items-center justify-center">
              <Hammer className="w-5 h-5 text-indigo-400" />
            </div>
            <div>
              <h1 className="text-sm font-semibold text-white">Multi-Client Quote Compilation Desk</h1>
              <p className="text-[10px] text-gray-500 mt-0.5">
                Intake raw excel Sheets of multi-tab Bills of Quantities and compile them into distinct parallel UCIDs.
              </p>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <div className="flex items-center gap-2">
              <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold font-mono transition-all duration-300 ${
                step >= 1 ? 'bg-indigo-500 text-white shadow-lg shadow-indigo-500/20' : 'bg-surface-elevated text-gray-500 border border-white/5'
              }`}>
                {step > 1 || isIngested ? <Check className="w-3.5 h-3.5" /> : '1'}
              </div>
              <span className={`font-semibold tracking-tight ${step === 1 ? 'text-indigo-400 font-bold' : 'text-gray-400'}`}>BOQ Intake Parse</span>
            </div>
            <div className="w-6 h-px bg-white/10" />
            <div className="flex items-center gap-2">
              <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold font-mono transition-all duration-300 ${
                step === 2 ? 'bg-indigo-500 text-white shadow-lg shadow-indigo-500/20' : 'bg-surface-elevated text-gray-500 border border-white/5'
              }`}>
                2
              </div>
              <span className={`font-semibold tracking-tight ${step === 2 ? 'text-indigo-400 font-bold' : 'text-gray-500'}`}>UCID Assignment Map</span>
            </div>
          </div>
        </div>

        {step === 1 ? (
          <StepIntake
            activeUcidsCount={ucids.length}
            onProceed={() => setStep(2)}
            onSimulationLoad={() => setIsIngested(true)}
          />
        ) : (
          <StepWorkspace
            solutionName={solutionName}
            setSolutionName={setSolutionName}
            isMultiUcid={isMultiUcid}
            toggleMultiUcidMode={toggleMultiUcidMode}
            handleAddUcid={handleAddUcid}
            configs={configs}
            selectedConfigId={selectedConfigId}
            setSelectedConfigId={setSelectedConfigId}
            ucidsList={ucidsList}
            assignConfigToUcid={assignConfigToUcid}
            updateContainerName={updateContainerName}
            updateContainerReasoning={updateContainerReasoning}
            toggleContainerLock={toggleContainerLock}
            ucids={ucids}
            handleDeployToMissionControl={handleDeployToMissionControl}
          />
        )}
      </motion.div>
  </ErrorBoundary>
  );
});

import React, { useState } from "react";
import {
  UploadCloud,
  CheckCircle,
  RefreshCw,
  Sparkles,
  ArrowRight,
  Check,
} from "lucide-react";
import { StatusBadge } from "../shared/StatusBadge";
import { apiClient } from "../../services/apiClient";

interface StepIntakeProps {
  activeUcidsCount: number;
  onProceed: () => void;
  onSimulationLoad: (fileName: string) => void;
}

export function StepIntake({
  activeUcidsCount,
  onProceed,
  onSimulationLoad,
}: StepIntakeProps) {
  const [isDragging, setIsDragging] = useState(false);
  const [isIngesting, setIsIngesting] = useState(false);
  const [ingestProgress, setIngestProgress] = useState(0);
  const [isIngested, setIsIngested] = useState(false);
  const [uploadedFileName, setUploadedFileName] = useState("");

  const handleFileUpload = async (fileName: string) => {
    setIsIngesting(true);
    setUploadedFileName(fileName);
    setIngestProgress(10);
    try {
      await apiClient.post("/api/boq/ingest", {
        fileName,
        presetType: "hpe-legacy"
      });
      setIngestProgress(100);
      setIsIngesting(false);
      setIsIngested(true);
      if (onSimulationLoad) {
        onSimulationLoad(fileName);
      }
    } catch (err) {
      setIsIngesting(false);
      // Handle error visually if necessary
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = () => {
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      handleFileUpload(e.dataTransfer.files[0].name);
    }
  };

  const triggerPicker = () => {
    const fileInput = document.getElementById(
      "boq-file-picker",
    ) as HTMLInputElement;
    if (fileInput) fileInput.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      handleFileUpload(e.target.files[0].name);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-fadeIn">
      {/* Main Intake Canvas */}
      <div className="lg:col-span-2 space-y-4">
        {/* Unified Pipeline Active Banner */}
        <div className="p-3 bg-indigo-500/5 border border-indigo-500/15 rounded-xl flex items-center justify-between text-left gap-4">
          <div>
            <div className="flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-indigo-400 animate-pulse shrink-0" />
              <span className="text-[9px] font-bold text-indigo-400 font-mono uppercase tracking-wider">
                Sourcing State Sync Connected
              </span>
            </div>
            <p className="text-[10px] text-gray-400 mt-1 leading-normal">
              Any specification uploaded or demo loaded in this Configurator instantly binds to the central <span className="text-gray-300 font-medium">Opportunities Ledger</span>, and feeds metrics straight into your parallel tracking dashboards.
            </p>
          </div>
          <div className="text-right shrink-0">
            <span className="text-[10px] font-mono text-emerald-400 font-bold block">
              Active Sync
            </span>
            <span className="text-[9px] text-gray-500 font-sans block mt-0.5 animate-fadeIn">
              Active Accounts: {activeUcidsCount}
            </span>
          </div>
        </div>

        <div className="bg-surface-elevated border border-white/5 rounded-xl p-6 space-y-6">
          <div className="flex items-start gap-4">
            <div className="w-12 h-12 rounded-xl bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center shrink-0 text-indigo-400">
              <UploadCloud className="w-6 h-6" />
            </div>
            <div>
              <StatusBadge status="Direct Solution Ingest" variant="info" />
              <h3 className="text-sm font-semibold text-white mt-1.5 font-sans">
                Bill of Quantities (BOQ) Ingestion
              </h3>
              <p className="text-[11px] text-gray-400 mt-1 leading-relaxed">
                Upload your customer hardware requirements sheet,
                cross-vendor BOQ workbook, or raw equipment PARTS spec file.
                The system will dynamically resolve nomenclature, run rules
                validators, and seed dual-sourcing mapping cards.
              </p>
            </div>
          </div>

          <div className="space-y-4">
            <div className="p-4 rounded-lg bg-indigo-500/[0.02] border border-indigo-500/10 flex flex-col sm:flex-row items-center justify-between gap-4">
              <p className="text-gray-400 text-[10.5px] max-w-sm text-center sm:text-left leading-normal">
                Don't have a spreadsheet handy? Click here to instantly
                parse a pre-scanned mock enterprise server &amp; storage
                workbook.
              </p>
              <button
                onClick={() =>
                  handleFileUpload("demographic_sourcing_specs_2026.xlsx")
                }
                className="px-4 py-2 rounded-lg bg-indigo-500 hover:bg-indigo-600 text-white font-bold cursor-pointer text-[10px] font-sans flex items-center gap-2 shrink-0 transition"
              >
                <Sparkles className="w-3.5 h-3.5 text-yellow-300" />
                <span>Load Demo BOQ</span>
              </button>
            </div>

            <div
              onDragOver={handleDragOver}
              onDragLeave={handleDragLeave}
              onDrop={handleDrop}
              className={`p-8 border-2 border-dashed rounded-xl flex flex-col items-center justify-center gap-3 transition ${
                isDragging
                  ? "border-indigo-400 bg-indigo-500/10"
                  : "border-indigo-500/10 bg-black/25"
              }`}
            >
              {isIngesting ? (
                <div className="flex flex-col items-center gap-2">
                  <RefreshCw className="w-8 h-8 text-indigo-400 animate-spin" />
                  <p className="font-semibold text-white font-sans text-xs">
                    Parsing Complex BOQ Sheet...
                  </p>
                  <div className="w-48 h-1.5 bg-white/5 rounded-full overflow-hidden">
                    <div
                      className="h-full bg-indigo-500 transition-all duration-200"
                      style={{ width: `${ingestProgress}%` }}
                    />
                  </div>
                </div>
              ) : isIngested ? (
                <div className="flex flex-col items-center text-center gap-2">
                  <CheckCircle className="w-8 h-8 text-emerald-400" />
                  <p className="font-semibold text-white">
                    Successfully Analyzed "{uploadedFileName}"
                  </p>
                  <p className="text-[10px] text-gray-500">
                    Extracted and normalized configuration options matched
                    with active enterprise contracts.
                  </p>
                  <button
                    onClick={onProceed}
                    className="mt-2 px-4 py-2 bg-indigo-500 hover:bg-indigo-600 text-white font-bold rounded-lg cursor-pointer transition flex items-center gap-1 focus:outline-none"
                  >
                    <span>Configure UCID Assignment</span>
                    <ArrowRight className="w-4 h-4" />
                  </button>
                </div>
              ) : (
                <div
                  className="flex flex-col items-center text-center gap-2 cursor-pointer w-full"
                  onClick={triggerPicker}
                >
                  <UploadCloud className="w-10 h-10 text-indigo-400" />
                  <p className="font-semibold text-gray-200">
                    Drag &amp; Drop or Upload Customer BOQ Spreadsheet
                  </p>
                  <p className="text-[10px] text-gray-500">
                    Supports multi-vendor, multi-tab equipment configuration
                    sheets
                  </p>
                  <button
                    type="button"
                    onClick={triggerPicker}
                    className="mt-2 px-3 py-1.5 bg-surface-elevated hover:bg-black/40 text-gray-300 font-medium rounded-lg text-[10px] border border-white/10"
                  >
                    Select File
                  </button>
                  <input
                    id="boq-file-picker"
                    type="file"
                    accept=".xlsx,.csv,.xls"
                    className="hidden"
                    onChange={handleFileChange}
                  />
                </div>
              )}
            </div>
          </div>

          <div className="pt-4 border-t border-white/5 flex flex-col sm:flex-row justify-between items-center gap-3">
            <div className="text-left">
              <p className="text-xs font-bold text-gray-300">
                Have active configurations in memory?
              </p>
              <p className="text-[10px] text-gray-500 mt-0.5">
                We detected {activeUcidsCount} active tracking UCID container(s)
                pre-loaded.
              </p>
            </div>
            <button
              onClick={onProceed}
              className="px-5 py-2.5 rounded-lg bg-surface-elevated hover:bg-surface-elevated text-indigo-400 font-bold border border-indigo-500/20 hover:border-indigo-500/40 cursor-pointer transition flex items-center gap-1.5 focus:outline-none text-[10px]" 
            >
              <span>Proceed to Assignment Map (Step 2)</span>
              <ArrowRight className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>

      {/* Guide Checklist Side Card */}
      <div className="space-y-4">
        {/* Pre-Condition Check */}
        <div className="bg-surface-elevated border border-white/5 rounded-xl p-5 space-y-3.5">
          <h4 className="font-bold text-white uppercase tracking-wider text-[10px]">
            Pre-Condition Verification
          </h4>
          <div className="space-y-3">
            <div className="flex items-center justify-between text-[11px] py-1 border-b border-white/5 pb-2">
              <span className="text-gray-400 font-sans font-medium">
                BOQ Document Ingested
              </span>
              <StatusBadge 
                status={isIngested ? "ACCEPTED" : "AWAITING"}
                variant={isIngested ? "success" : "error"}
                size="sm"
              />
