import React, { useState, useMemo } from 'react';
import { 
  Network, 
  RefreshCw, 
  ZoomIn, 
  ZoomOut, 
  RotateCcw, 
  Filter, 
  CheckCircle2, 
  AlertTriangle, 
  ShieldCheck, 
  Zap, 
  HelpCircle,
  Cpu,
  Layers,
  ArrowRight,
  UserCheck,
  Link,
  Plus
} from 'lucide-react';
import { motion, AnimatePresence } from "motion/react";
import { useCatalogGraphData } from "../../hooks/useCatalogGraphData";
import { GraphNode } from "../../types/data";
import type { Config, CatalogSKU, Vendor } from "../../types";
import { tokens } from "../../styles/tokens";
import { useToast } from "../shared/ToastContext";
import { apiClient } from "../../services/apiClient";

const DEFAULT_CONFIGS = [{ id: "cfg-base", vendor: "HPE" } as Config];

interface TaxonomyGraphViewProps {
  catalogSkus: CatalogSKU[];
  setCatalogSkus: React.Dispatch<React.SetStateAction<CatalogSKU[]>>;
  vendors: Vendor[];
}

export function TaxonomyGraphView({ catalogSkus, setCatalogSkus, vendors }: TaxonomyGraphViewProps) {
  const { toast } = useToast();
  const { data, isLoading, mapNode, unmapNode, addRule, refresh } = useCatalogGraphData(
    "cfg-base", 
    DEFAULT_CONFIGS, 
    catalogSkus
  );

  // States
  const [expandedNode, setExpandedNode] = useState<string | null>(null);
  const [filterOrphansOnly, setFilterOrphansOnly] = useState(false);
  const [zoom, setZoom] = useState(1);
  const [pan, setPan] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  // Constraint Checker States
  const [selectedChassis, setSelectedChassis] = useState("");
  const [selectedCpu, setSelectedCpu] = useState("");
  const [ramQty, setRamQty] = useState(8);
  const [psuWatts, setPsuWatts] = useState(1600);
  const [isValidatingConstraints, setIsValidatingConstraints] = useState(false);
  const [validationResult, setValidationResult] = useState<any>(null);
  const [activeTab, setActiveTab] = useState<"constraints" | "orphans">("constraints");
  const [selectedOrphanToMap, setSelectedOrphanToMap] = useState<string | null>(null);

  // Zoom & Pan functions
  const handleZoomIn = () => setZoom(z => Math.min(z + 0.1, 1.8));
  const handleZoomOut = () => setZoom(z => Math.max(z - 0.1, 0.5));
  const handleResetZoom = () => {
    setZoom(1);
    setPan({ x: 0, y: 0 });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if ((e.target as HTMLElement).closest(".node-card") || (e.target as HTMLElement).closest("button") || (e.target as HTMLElement).closest("select")) {
      return;
    }
    setIsDragging(true);
    setDragStart({ x: e.clientX - pan.x, y: e.clientY - pan.y });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    setPan({
      x: e.clientX - dragStart.x,
      y: e.clientY - dragStart.y
    });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const toggleNode = (nodeId: string) => {
    setExpandedNode(prev => prev === nodeId ? null : nodeId);
  };

  // Filter lists of nodes
  const rootNodes = useMemo(() => data.nodes.filter(n => n.type === "product"), [data.nodes]);
  const categories = useMemo(() => data.nodes.filter(n => n.type === "category"), [data.nodes]);
  const skus = useMemo(() => data.nodes.filter(n => n.type === "sku"), [data.nodes]);

  // Chassis & Processor options for constraint validator dropdowns
  const chassisOptions = useMemo(() => catalogSkus.filter(s => s.type === "Chassis" && s.status === "active"), [catalogSkus]);
  const cpuOptions = useMemo(() => catalogSkus.filter(s => s.type === "Processor" && s.status === "active"), [catalogSkus]);

  // Handle mechanical check post
  const handleValidateConstraints = async () => {
    if (!selectedChassis || !selectedCpu) {
      toast("Please select a Chassis SKU and CPU SKU to check compatibility.", "warn");
      return;
    }
    setIsValidatingConstraints(true);
    setValidationResult(null);
    try {
      const res = await apiClient.post("/api/taxonomy/check-constraints", {
        chassisSku: selectedChassis,
        cpuSku: selectedCpu,
        ramQty,
        psuWatts
      });
      if (res.success) {
        setValidationResult(res.data);
        toast("Hardware constraint metrics calculated successfully.", "success");
      } else {
        toast("Mechanical validation rejected.", "error");
      }
    } catch (err) {
      toast("Failed to validate server physical constraints.", "error");
    } finally {
      setIsValidatingConstraints(false);
    }
  };

  // Handle map orphan node re-assignment
  const handleMapOrphanNode = async (orphanId: string, categoryId: string) => {
    const orphanNodeName = catalogSkus.find(s => s.partNumber === orphanId || s.id === orphanId)?.name || "Mapped Item";

    // Deduce type from Category ID
    let type = "Unknown";
    if (categoryId.includes("Processor")) type = "Processor";
    else if (categoryId.includes("Memory")) type = "Memory";
    else if (categoryId.includes("Storage")) type = "Storage";
    else if (categoryId.includes("Controller")) type = "Controller";
    else if (categoryId.includes("Network")) type = "Network";
    else if (categoryId.includes("Power")) type = "Power";
    else if (categoryId.includes("Cooling")) type = "Cooling";
    else if (categoryId.includes("Chassis")) type = "Chassis Option";

    try {
      await mapNode(orphanId, categoryId, { partNumber: orphanId, name: orphanNodeName, type });

      // Update global state of catalog SKUs
      setCatalogSkus(prev => prev.map(s => {
        if (s.partNumber === orphanId) {
          return {
            ...s,
            type: type,
            status: "active" as const
          };
        }
        return s;
      }));

      setSelectedOrphanToMap(null);
      toast(`Successfully mapped ${orphanId} to ${type} Category node.`, "success");
    } catch (e) {
      toast("Failed to commit mapping to server state.", "error");
    }
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6 w-full h-full max-w-7xl mx-auto text-white">
      {/* LEFT: Interactive Taxonomy Tree Graph Canvas */}
      <div className="flex-1 flex flex-col gap-4">
        {/* Header Controls */}
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 p-4 bg-surface-card border border-white/5 rounded-xl">
          <div>
            <h2 className="text-sm font-bold text-white flex items-center gap-2 uppercase tracking-wider">
              <Network className="w-4 h-4 text-indigo-400" />
              Taxonomy Graph Canvas
            </h2>
            <p className="text-[11px] text-gray-400 mt-0.5">
              Drag to pan. Scroll or use buttons to zoom. Click nodes to inspect constraints.
            </p>
          </div>

          <div className="flex items-center gap-2 flex-wrap">
            <button 
              onClick={() => setFilterOrphansOnly(!filterOrphansOnly)}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg border text-xs font-mono transition-all cursor-pointer ${filterOrphansOnly ? 'bg-amber-500/20 border-amber-500/40 text-amber-300 font-bold' : 'bg-surface-elevated border-white/5 text-gray-400 hover:text-white'}`}
            >
              <Filter className="w-3.5 h-3.5" />
              <span>{filterOrphansOnly ? 'Showing Orphans' : 'Filter Orphans'}</span>
            </button>

            <button 
              onClick={() => refresh()}
              disabled={isLoading}
              className="flex items-center gap-1.5 px-3 py-1.5 bg-indigo-500 hover:bg-indigo-600 disabled:opacity-50 text-xs font-bold rounded-lg border border-indigo-400/20 transition cursor-pointer text-white"
            >
              <RefreshCw className={`w-3.5 h-3.5 ${isLoading ? 'animate-spin' : ''}`} />
              <span>Refresh Topology</span>
            </button>
          </div>
        </div>

        {/* Viewport Canvas Container */}
        <div 
          className="relative flex-1 w-full bg-surface-card border border-indigo-500/10 rounded-xl overflow-hidden min-h-[560px] select-none cursor-grab active:cursor-grabbing"
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={handleMouseUp}
        >
          {/* Subtle Grid Background */}
          <div 
            className="absolute inset-0 opacity-[0.03]" 
            style={{ 
              backgroundImage: "linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)", 
              backgroundSize: "24px 24px" 
            }} 
          />

          {/* Floating Zoom & Position Controls */}
          <div className="absolute top-4 left-4 z-30 flex items-center gap-1 bg-black/60 border border-white/10 rounded-lg p-1">
            <button 
              onClick={handleZoomIn} 
              className="p-1.5 hover:bg-white/10 text-gray-400 hover:text-white rounded transition cursor-pointer border-0" 
              title="Zoom In"
            >
              <ZoomIn className="w-4 h-4" />
            </button>
            <button 
              onClick={handleZoomOut} 
              className="p-1.5 hover:bg-white/10 text-gray-400 hover:text-white rounded transition cursor-pointer border-0" 
              title="Zoom Out"
            >
              <ZoomOut className="w-4 h-4" />
            </button>
            <div className="w-[1px] h-4 bg-white/10 mx-1" />
            <button 
              onClick={handleResetZoom} 
              className="p-1.5 hover:bg-white/10 text-gray-400 hover:text-white rounded transition text-[10px] font-mono font-bold cursor-pointer border-0" 
              title="Reset View"
            >
              <RotateCcw className="w-3.5 h-3.5" />
            </button>
            <span className="text-[9px] font-mono text-gray-400 px-1">{Math.round(zoom * 100)}%</span>
          </div>

          {/* Transforming Graph Node Content */}
          <div 
            className="absolute inset-0 flex flex-col items-center justify-start p-16 transition-transform duration-75 ease-out origin-top-left"
            style={{
              transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})`,
              width: "100%",
              height: "100%"
            }}
          >
            {isLoading ? (
              <div className="m-auto flex flex-col items-center gap-3">
                <RefreshCw className="w-8 h-8 text-indigo-400 animate-spin" />
                <span className="text-xs font-mono text-indigo-300">Synchronizing Sourcing Tree...</span>
              </div>
            ) : (
              <div className="flex flex-col items-center gap-16 min-w-max p-12">
                {/* Level 1: System Base configuration */}
                <div className="flex justify-center">
                  {rootNodes.map(node => (
                    <motion.div 
                      key={node.id}
                      onClick={() => toggleNode(node.id)}
                      className={`node-card p-4 rounded-xl border flex flex-col items-center justify-center text-center cursor-pointer transition-all shadow-lg w-56 bg-surface-elevated/90 relative ${
                        expandedNode === node.id ? 'border-indigo-400 shadow-indigo-500/20 shadow-md scale-105' : 'border-indigo-500/30'
                      }`}
                      whileHover={{ y: -2 }}
                    >
                      <span className="text-[10px] font-mono font-bold text-indigo-400 uppercase tracking-widest mb-1">Target Engine Base</span>
                      <span className="text-xs font-bold text-white font-mono">{node.label}</span>
                      <span className="text-[9px] text-gray-400 mt-1 max-w-[190px] truncate">{node.sublabel}</span>

                      <AnimatePresence>
                        {expandedNode === node.id && (
                          <motion.div 
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: 10 }}
                            className="absolute top-24 w-60 bg-black/95 border border-indigo-500/30 rounded-xl p-3 text-left shadow-2xl z-40"
                            onClick={e => e.stopPropagation()}
                          >
                            <span className="text-[9px] font-bold text-indigo-300 block mb-1.5 uppercase font-mono">Structural Rules</span>
                            <div className="space-y-1 text-[9px] text-gray-300">
                              {node.constraints?.map((c, idx) => (
                                <div key={idx} className="flex items-start gap-1">
                                  <span className="text-indigo-400 font-bold">•</span>
                                  <span>{c}</span>
                                </div>
                              )) || <div>No specific base rules.</div>}
                            </div>
                          </motion.div>
                        )}
                      </AnimatePresence>
                    </motion.div>
                  ))}
                </div>

                {/* Vertical Connector lines */}
                {rootNodes.length > 0 && categories.length > 0 && (
                  <div className="w-[1.5px] h-10 bg-indigo-500/20 -mt-16 z-0" />
                )}

                {/* Level 2 & 3: Category Nodes with children items grouped underneath */}
                <div className="flex gap-10 justify-center items-start flex-wrap -mt-8">
                  {categories.map(cat => {
                    const mappedSkus = skus.filter(s => 
                      data.edges.some(e => e.source === cat.id && e.target === s.id)
                    );

                    // Skip category rendering if filterOrphansOnly is active and this has no orphans
                    const hasOrphansInCategory = mappedSkus.some(s => data.unmappedIds.includes(s.id));
                    if (filterOrphansOnly && !hasOrphansInCategory) return null;

                    return (
                      <div key={cat.id} className="flex flex-col items-center gap-6 p-4 rounded-xl bg-indigo-900/5 border border-indigo-500/5">
                        {/* Category Label Card */}
                        <div 
                          className="p-3 rounded-lg border border-indigo-500/20 bg-surface-elevated w-48 text-center"
                        >
                          <span className="text-[10px] text-indigo-300 font-bold uppercase tracking-wider block font-mono">
                            {cat.label.replace(" Subsystem", "")}
                          </span>
                          <span className="text-[8px] text-gray-500 font-mono mt-0.5 block uppercase">
                            {mappedSkus.length} Configured Parts
                          </span>
                        </div>

                        {/* SKUs under Category */}
                        <div className="flex flex-col gap-3.5 w-48">
                          {mappedSkus.map(child => {
                            const isOrphan = data.unmappedIds.includes(child.id);

                            return (
                              <motion.div 
                                key={child.id}
                                onClick={() => toggleNode(child.id)}
                                className={`node-card p-2.5 rounded-lg border text-left cursor-pointer transition-all w-full relative ${
                                  isOrphan 
                                    ? 'border-rose-500/40 bg-rose-500/5 hover:bg-rose-500/10 shadow-lg shadow-rose-950/20' 
                                    : expandedNode === child.id 
                                      ? 'border-indigo-400 bg-indigo-950/30' 
                                      : 'border-white/5 bg-surface-elevated/70 hover:bg-surface-elevated'
                                }`}
                                whileHover={{ scale: 1.02 }}
                              >
                                <div className="flex justify-between items-center gap-1">
                                  <span className={`text-[10px] font-bold font-mono truncate ${isOrphan ? 'text-rose-400' : 'text-gray-300'}`}>
                                    {child.label}
                                  </span>
                                  {isOrphan && (
                                    <span className="text-[8px] font-mono px-1 py-0.2 rounded bg-rose-500/20 text-rose-300 border border-rose-500/30 animate-pulse">
                                      ORPHAN
                                    </span>
                                  )}
                                </div>
                                <p className="text-[9px] text-gray-500 mt-1 truncate max-w-[160px]">{child.sublabel}</p>

                                <AnimatePresence>
                                  {expandedNode === child.id && (
                                    <motion.div 
                                      initial={{ opacity: 0, scale: 0.95 }}
                                      animate={{ opacity: 1, scale: 1 }}
                                      exit={{ opacity: 0, scale: 0.95 }}
                                      className="absolute top-14 left-0 right-0 bg-black/95 border border-indigo-500/30 rounded-xl p-3 text-left shadow-2xl z-40"
                                      onClick={e => e.stopPropagation()}
                                    >
                                      <span className="text-[9px] font-bold text-indigo-300 block mb-1 uppercase font-mono">Constraints</span>
                                      <div className="space-y-1 text-[8.5px] text-gray-300 leading-snug">
                                        {child.constraints?.map((c, i) => (
                                          <div key={i} className="flex items-start gap-1">
                                            <span className="text-indigo-400 font-bold">•</span>
                                            <span>{c}</span>
                                          </div>
                                        )) || <div>No constraints specified.</div>}
                                      </div>
                                    </motion.div>
                                  )}
                                </AnimatePresence>
                              </motion.div>
                            );
                          })}
                        </div>
                      </div>
                    );
                  })}
                </div>

                {/* Orphaned Box at bottom if not filtered out */}
                {data.unmappedIds.length > 0 && !filterOrphansOnly && (
                  <div className="mt-6 p-5 border border-rose-500/25 bg-rose-500/5 rounded-xl text-center max-w-2xl w-full">
                    <div className="flex items-center justify-center gap-2 mb-4">
                      <AlertTriangle className="w-4.5 h-4.5 text-rose-400 animate-pulse" />
                      <h3 className="text-xs font-bold text-rose-400 uppercase tracking-widest font-mono">
                        Orphaned Sourcing Components Detected ({data.unmappedIds.length})
                      </h3>
                    </div>
                    <p className="text-[10px] text-gray-400 max-w-lg mx-auto mb-4 leading-normal">
                      The mechanical intelligence scanner found unmapped items lacking categorization boundaries. 
                      Use the Orphan Management Workshop on the right side panel to align these SKUs.
                    </p>

                    <div className="flex gap-3.5 justify-center flex-wrap">
                      {skus.filter(s => data.unmappedIds.includes(s.id)).map(orphan => (
                        <div 
                          key={orphan.id}
                          className="p-2 bg-black/40 border border-rose-500/30 rounded-lg text-left flex flex-col gap-1 w-44 hover:border-rose-400 transition"
                        >
                          <span className="text-[10px] font-mono font-bold text-rose-300">{orphan.label}</span>
                          <span className="text-[8.5px] text-gray-400 truncate block">{orphan.sublabel}</span>
                          <button 
                            onClick={() => {
                              setSelectedOrphanToMap(orphan.id);
                              setActiveTab("orphans");
                            }}
                            className="mt-1 text-[8.5px] font-bold text-rose-400 hover:text-rose-300 uppercase tracking-wide cursor-pointer text-left border-0 bg-transparent flex items-center gap-0.5"
                          >
                            <Plus className="w-3 h-3" /> Auto-Map SKU
                          </button>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* RIGHT: Mechanical Validation & Orphan Repair Workshop */}
      <div 
        className="w-full lg:w-80 p-5 rounded-xl border flex flex-col gap-4 bg-surface-card"
        style={{ borderColor: "rgba(74, 133, 253, 0.08)" }}
      >
        {/* Tab Selection */}
        <div className="flex border-b border-white/5 pb-1">
          <button 
            onClick={() => setActiveTab("constraints")}
            className={`flex-1 pb-2 text-xs font-bold font-mono tracking-wider cursor-pointer uppercase transition-colors text-center border-0 bg-transparent ${
              activeTab === "constraints" ? 'text-indigo-400 border-b-2 border-indigo-400' : 'text-gray-500 hover:text-gray-300'
            }`}
          >
            Mechanical Check
          </button>
          <button 
            onClick={() => setActiveTab("orphans")}
            className={`flex-1 pb-2 text-xs font-bold font-mono tracking-wider cursor-pointer uppercase transition-colors text-center border-0 bg-transparent ${
              activeTab === "orphans" ? 'text-indigo-400 border-b-2 border-indigo-400' : 'text-gray-500 hover:text-gray-300'
            }`}
          >
            Orphan Workshop
          </button>
        </div>

        {/* Tab 1: Mechanical Constraints Check */}
        {activeTab === "constraints" && (
          <div className="space-y-4 flex-1 flex flex-col justify-between">
            <div className="space-y-3.5">
              <div className="text-[10px] font-bold uppercase tracking-wider text-indigo-300 flex items-center gap-1.5 font-mono">
                <ShieldCheck className="w-4 h-4 text-indigo-400" />
                Socket Compatibility Tester
              </div>
              <p className="text-[10px] text-gray-400 leading-normal">
                Test logical pins, RAM channels, and thermal configurations before submitting design alternatives to vendor pipelines.
              </p>

              {/* Chassis SKU */}
              <div className="space-y-1.5">
                <label className="text-[9px] font-mono text-gray-400 uppercase font-bold tracking-wide">
                  Chassis Form Factor
                </label>
                <select
                  value={selectedChassis}
                  onChange={e => setSelectedChassis(e.target.value)}
                  className="w-full bg-black/40 border border-white/10 rounded-lg p-2 text-xs focus:ring-1 focus:ring-indigo-500 text-white"
                >
                  <option value="" className="bg-surface-elevated">-- Select Target Chassis --</option>
                  {chassisOptions.map(c => (
                    <option key={c.id} value={c.partNumber} className="bg-surface-elevated">
                      {c.partNumber} — {c.name.split("Chassis")[0]?.trim() || c.name}
                    </option>
                  ))}
                </select>
              </div>

              {/* CPU SKU */}
              <div className="space-y-1.5">
                <label className="text-[9px] font-mono text-gray-400 uppercase font-bold tracking-wide">
                  Processor Socket Architecture
                </label>
                <select
                  value={selectedCpu}
                  onChange={e => setSelectedCpu(e.target.value)}
                  className="w-full bg-black/40 border border-white/10 rounded-lg p-2 text-xs focus:ring-1 focus:ring-indigo-500 text-white"
                >
                  <option value="" className="bg-surface-elevated">-- Select Sourced CPU --</option>
                  {cpuOptions.map(cpu => (
                    <option key={cpu.id} value={cpu.partNumber} className="bg-surface-elevated">
                      {cpu.partNumber} — {cpu.name.replace("Processor", "").trim()}
                    </option>
                  ))}
                </select>
              </div>

              {/* RAM Quantity */}
              <div className="space-y-1.5">
                <label className="text-[9px] font-mono text-gray-400 uppercase font-bold tracking-wide">
                  DDR5 Memory Quantity (DIMMs)
                </label>
                <input
                  type="number"
                  min="1"
                  max="32"
                  value={ramQty}
                  onChange={e => setRamQty(Number(e.target.value))}
                  className="w-full bg-black/40 border border-white/10 rounded-lg p-2 text-xs focus:ring-1 focus:ring-indigo-500 text-white font-mono"
                />
              </div>

              {/* Power PSU Watts */}
              <div className="space-y-1.5">
                <label className="text-[9px] font-mono text-gray-400 uppercase font-bold tracking-wide">
                  Power Supply Capacity (Watts)
                </label>
                <input
                  type="number"
                  step="100"
                  min="500"
                  max="3000"
                  value={psuWatts}
                  onChange={e => setPsuWatts(Number(e.target.value))}
                  className="w-full bg-black/40 border border-white/10 rounded-lg p-2 text-xs focus:ring-1 focus:ring-indigo-500 text-white font-mono"
                />
              </div>
            </div>

            <div className="space-y-3 pt-4 border-t border-white/5">
              {/* Validation Result Box */}
              {validationResult && (
                <div 
                  className="p-3.5 rounded-lg text-[10px] space-y-2 border border-emerald-500/20 bg-emerald-500/5 animate-fadeIn"
                >
                  <div className="flex items-center gap-1.5 text-emerald-400 font-bold font-mono">
                    <ShieldCheck className="w-4 h-4 shrink-0" />
                    <span>SOCKET METRICS MATCHED</span>
                  </div>
                  <div className="grid grid-cols-2 gap-1.5 font-mono text-[9px] text-gray-300">
                    <div>Chassis Pin: <span className="text-white">{validationResult.chassisSocket}</span></div>
                    <div>CPU Socket: <span className="text-white">{validationResult.cpuSocket}</span></div>
                    <div>RAM Allocation: <span className="text-emerald-400">{validationResult.memoryChannels}</span></div>
                    <div>Storage Controller: <span className="text-emerald-400">{validationResult.storageController}</span></div>
                  </div>
                </div>
              )}

              <button
                onClick={handleValidateConstraints}
                disabled={isValidatingConstraints}
                className="w-full flex items-center justify-center gap-2 py-2.5 bg-indigo-500 hover:bg-indigo-600 disabled:opacity-50 text-white font-bold rounded-lg border border-indigo-400/20 transition cursor-pointer text-xs uppercase font-mono shadow-md"
              >
                {isValidatingConstraints ? (
                  <>
                    <RefreshCw className="w-3.5 h-3.5 animate-spin" /> Checking Pins...
                  </>
                ) : (
                  <>
                    <Zap className="w-3.5 h-3.5 text-indigo-300" /> Validate Constraints
                  </>
                )}
              </button>
            </div>
          </div>
        )}

        {/* Tab 2: Orphan Management Desk */}
        {activeTab === "orphans" && (
          <div className="flex-1 flex flex-col justify-between gap-4">
            <div className="space-y-3.5">
              <div className="text-[10px] font-bold uppercase tracking-wider text-amber-400 flex items-center gap-1.5 font-mono">
                <Layers className="w-4 h-4 text-amber-400 animate-pulse" />
                Orphan Alignment Desk
              </div>
              <p className="text-[10px] text-gray-400 leading-normal">
                Mapping orphaned SKUs establishes critical boundaries and prevents unbuildable config loops.
              </p>

              {/* Selected Orphan Box */}
              {selectedOrphanToMap ? (
                <div className="p-3 bg-indigo-950/20 border border-indigo-500/20 rounded-lg space-y-3 animate-fadeIn text-xs">
                  <div>
                    <span className="text-[9px] font-mono text-gray-400 uppercase block">Aligning Part</span>
                    <strong className="text-indigo-300 font-mono text-xs">{selectedOrphanToMap}</strong>
                    <p className="text-[9px] text-gray-400 mt-0.5">
                      {catalogSkus.find(s => s.partNumber === selectedOrphanToMap)?.name || "Raw component metadata"}
                    </p>
                  </div>

                  <div className="space-y-1.5 pt-2 border-t border-white/5">
                    <label className="text-[9px] font-mono text-gray-400 uppercase font-bold tracking-wide block">
                      Target Subsystem Category
                    </label>
                    <select
                      onChange={e => handleMapOrphanNode(selectedOrphanToMap, e.target.value)}
                      defaultValue=""
                      className="w-full bg-black/60 border border-white/10 rounded-lg p-2 text-xs focus:ring-1 focus:ring-indigo-500 text-white"
                    >
                      <option value="" disabled>-- Choose Subsystem --</option>
                      {categories.map(cat => (
                        <option key={cat.id} value={cat.id} className="bg-surface-elevated">
                          {cat.label}
                        </option>
                      ))}
                    </select>
                  </div>

                  <button 
                    onClick={() => setSelectedOrphanToMap(null)}
                    className="w-full text-center text-[9px] font-mono text-gray-500 hover:text-gray-300 border-0 bg-transparent cursor-pointer"
                  >
                    Cancel Action
                  </button>
                </div>
              ) : (
                <div className="p-4 border border-dashed border-white/10 rounded-lg text-center text-[10px] text-gray-500 flex flex-col items-center justify-center min-h-[140px] gap-2">
                  <HelpCircle className="w-8 h-8 text-gray-600" />
                  <p>Click "Auto-Map SKU" on any orphan node in the graph canvas to configure categorization boundaries.</p>
                </div>
              )}
            </div>

            {/* List of active orphans */}
            <div className="space-y-2 max-h-48 overflow-y-auto scrollbar-thin pr-1 pt-2 border-t border-white/5">
              <span className="text-[9px] font-mono text-gray-500 font-bold uppercase block tracking-wider mb-1">
                Active Orphans ({data.unmappedIds.length})
              </span>
              {data.unmappedIds.map(oId => {
                const sRef = catalogSkus.find(s => s.partNumber === oId || s.id === oId);
                return (
                  <div 
                    key={oId}
                    className="flex justify-between items-center p-2 rounded bg-black/25 border border-white/5 text-[10px] group hover:border-indigo-500/20"
                  >
                    <div className="min-w-0 pr-2">
                      <span className="font-mono text-rose-300 font-semibold block truncate">{oId}</span>
                      <span className="text-gray-500 text-[8.5px] block truncate">{sRef?.name || "Unstructured name"}</span>
                    </div>
                    <button
                      onClick={() => setSelectedOrphanToMap(oId)}
                      className="px-2 py-1 bg-indigo-500/10 hover:bg-indigo-500/25 border border-indigo-500/20 text-indigo-400 font-bold text-[9px] font-mono rounded cursor-pointer shrink-0 transition"
                    >
                      Map
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

